def github_ready():
    return bool(GITHUB_TOKEN and GITHUB_REPO and GITHUB_BRANCH and GITHUB_PATH)

def github_headers():
    return {
        "Authorization": f"Bearer {GITHUB_TOKEN}",
        "Accept": "application/vnd.github+json",
        "X-GitHub-Api-Version": "2022-11-28"
    }

def github_contents_url(path=None):
    p = path or GITHUB_PATH
    return f"https://api.github.com/repos/{GITHUB_REPO}/contents/{p}"

def github_get_file(path=None):
    if not github_ready():
        raise Exception("GitHub ENV не заполнены: GITHUB_TOKEN, GITHUB_REPO, GITHUB_BRANCH, GITHUB_PATH")

    r = requests.get(
        github_contents_url(path),
        headers=github_headers(),
        params={"ref": GITHUB_BRANCH},
        timeout=30
    )

    if r.status_code == 404:
        return None

    if r.status_code >= 300:
        raise Exception(f"GitHub GET error {r.status_code}: {r.text[:500]}")

    return r.json()




def github_get_file_bytes(path=None):
    """
    v19.11.8.4 LARGE FILE BACKUP FIX:
    GitHub Contents API may return empty content/encoding=none for main.py > 1 MB.
    For backup/admin health we must fetch raw bytes via blob API/download_url fallback.
    """
    meta = github_get_file(path)
    if not meta:
        return b"", None
    # Normal small-file path
    content = meta.get("content")
    if content:
        try:
            return base64.b64decode(content), meta
        except Exception:
            pass

    # Large-file path: use Git Blob API by sha
    sha = (meta.get("sha") or "").strip()
    if sha:
        try:
            r = requests.get(github_api_url(f"git/blobs/{sha}"), headers=github_headers(), timeout=40)
            if r.status_code < 300:
                js = r.json()
                blob_content = js.get("content") or ""
                if blob_content:
                    return base64.b64decode(blob_content), meta
        except Exception as e:
            print(f"github blob bytes fallback error: {e}")

    # Last fallback: raw download_url
    download_url = (meta.get("download_url") or "").strip()
    if download_url:
        try:
            r = requests.get(download_url, headers={"Authorization": f"Bearer {GITHUB_TOKEN}"}, timeout=40)
            if r.status_code < 300 and r.content:
                return r.content, meta
        except Exception as e:
            print(f"github download_url bytes fallback error: {e}")

    return b"", meta

def extract_bot_version_from_text(text):
    try:
        m = re.search(r'BOT_VERSION\s*=\s*["\']([^"\']+)["\']', text or "")
        return m.group(1).strip() if m else ""
    except Exception:
        return ""

def python_compile_file(path):
    """
    v18.3.1 ADMIN COMPILE FIX:
    Проверяет загруженный main*.py до отправки в GitHub.
    Возвращает текст файла для дальнейшего извлечения BOT_VERSION.
    """
    path = str(path)
    with open(path, "rb") as f:
        raw = f.read()

    # Проверка, что это действительно python-текст, а не txt/pdf/картинка с именем .py.
    try:
        text = raw.decode("utf-8")
    except UnicodeDecodeError:
        text = raw.decode("utf-8-sig", errors="strict")

    if "BOT_VERSION" not in text or "def " not in text:
        raise Exception("Файл не похож на полноценный main.py: нет BOT_VERSION или def.")

    import py_compile
    py_compile.compile(path, doraise=True)
    return text

def version_tuple(ver):
    """Грубое сравнение v18.2.2 > v18.2 > v18.1."""
    try:
        m = re.search(r'v\s*(\d+)\.(\d+)(?:\.(\d+))?', ver or "", re.I)
        if not m:
            return (0, 0, 0)
        return (int(m.group(1)), int(m.group(2)), int(m.group(3) or 0))
    except Exception:
        return (0, 0, 0)

def github_latest_main_version():
    try:
        raw, meta = github_get_file_bytes(GITHUB_PATH)
        if not raw:
            return ""
        txt = raw.decode("utf-8", errors="ignore")
        return extract_bot_version_from_text(txt)
    except Exception as e:
        print(f"github latest version check error: {e}")
        return ""

def github_put_file(path, content_bytes, message, sha=None):
    """
    v15.8:
    GitHub Contents API требует актуальный sha файла.
    Если два admin upload или background sync почти одновременно меняют main.py,
    GitHub возвращает 409: expected old sha, file already at new sha.
    В этом случае берём свежий sha и повторяем PUT.
    """
    last_error = None

    for attempt in range(3):
        payload = {
            "message": message,
            "content": base64.b64encode(content_bytes).decode("ascii"),
            "branch": GITHUB_BRANCH
        }

        if sha:
            payload["sha"] = sha

        r = requests.put(
            github_contents_url(path),
            headers=github_headers(),
            json=payload,
            timeout=40
        )

        if r.status_code < 300:
            return r.json()

        last_error = f"GitHub PUT error {r.status_code}: {r.text[:800]}"

        if r.status_code == 409:
            try:
                fresh = github_get_file(path)
                sha = fresh.get("sha") if fresh else None
                time.sleep(1 + attempt)
                continue
            except Exception as e:
                last_error = f"GitHub PUT 409 retry failed: {e}"
                break

        break

    raise Exception(last_error or "GitHub PUT failed")



# === v19.11.8.4 LARGE FILE BACKUP FIX ===
def _v191182_safe_backup_version_tag(version):
    """Make BOT_VERSION safe for GitHub backup filename."""
    try:
        tag = (version or "unknown").strip()
        tag = re.sub(r"[^A-Za-z0-9._-]+", "_", tag)
        tag = tag.strip("._-") or "unknown"
        return tag[:80]
    except Exception:
        return "unknown"


def _v191182_backup_path_for_current_main(current_text):
    """Create deterministic backup path for the currently deployed main.py."""
    old_version = extract_bot_version_from_text(current_text or "") or "unknown"
    stamp = datetime.utcnow().strftime("%Y%m%d_%H%M%S")
    return f"backups/main_backup_{stamp}_{_v191182_safe_backup_version_tag(old_version)}.py"


def github_api_url(path):
    return f"https://api.github.com/repos/{GITHUB_REPO}/{path.lstrip('/')}"


def github_create_blob(content_bytes):
    """Create a Git blob and return its sha."""
    r = requests.post(
        github_api_url("git/blobs"),
        headers=github_headers(),
        json={
            "content": base64.b64encode(content_bytes or b"").decode("ascii"),
            "encoding": "base64",
        },
        timeout=40,
    )
    if r.status_code >= 300:
        raise Exception(f"GitHub blob error {r.status_code}: {r.text[:600]}")
    return r.json().get("sha")


def github_put_files_atomic(file_map, message):
    """
    v19.11.8.2:
    Commit several files in one Git commit.
    This creates backups/<old>.py and updates main.py atomically, so Render Auto Deploy
    never sees a separate backup-only commit with the old main.py.
    file_map: {repo_path: bytes}
    """
    if not github_ready():
        raise Exception("GitHub ENV не заполнены: GITHUB_TOKEN, GITHUB_REPO, GITHUB_BRANCH, GITHUB_PATH")
    if not isinstance(file_map, dict) or not file_map:
        raise Exception("Нет файлов для atomic GitHub commit")

    ref_url = github_api_url(f"git/ref/heads/{GITHUB_BRANCH}")
    r = requests.get(ref_url, headers=github_headers(), timeout=30)
    if r.status_code >= 300:
        raise Exception(f"GitHub ref GET error {r.status_code}: {r.text[:600]}")
    base_commit_sha = ((r.json().get("object") or {}).get("sha") or "").strip()
    if not base_commit_sha:
        raise Exception("GitHub ref не вернул sha последнего commit")

    r = requests.get(github_api_url(f"git/commits/{base_commit_sha}"), headers=github_headers(), timeout=30)
    if r.status_code >= 300:
        raise Exception(f"GitHub commit GET error {r.status_code}: {r.text[:600]}")
    base_tree_sha = ((r.json().get("tree") or {}).get("sha") or "").strip()
    if not base_tree_sha:
        raise Exception("GitHub commit не вернул tree sha")

    tree_items = []
    for path, content_bytes in file_map.items():
        repo_path = str(path or "").strip().lstrip("/")
        if not repo_path:
            continue
        blob_sha = github_create_blob(content_bytes if isinstance(content_bytes, (bytes, bytearray)) else bytes(content_bytes))
        tree_items.append({
            "path": repo_path,
            "mode": "100644",
            "type": "blob",
            "sha": blob_sha,
        })

    if not tree_items:
        raise Exception("Atomic commit: нет валидных путей файлов")

    r = requests.post(
        github_api_url("git/trees"),
        headers=github_headers(),
        json={"base_tree": base_tree_sha, "tree": tree_items},
        timeout=40,
    )
    if r.status_code >= 300:
        raise Exception(f"GitHub tree error {r.status_code}: {r.text[:600]}")
    new_tree_sha = r.json().get("sha")

    r = requests.post(
        github_api_url("git/commits"),
        headers=github_headers(),
        json={"message": message, "tree": new_tree_sha, "parents": [base_commit_sha]},
        timeout=40,
    )
    if r.status_code >= 300:
        raise Exception(f"GitHub commit create error {r.status_code}: {r.text[:600]}")
    new_commit = r.json()
    new_commit_sha = new_commit.get("sha")
    if not new_commit_sha:
        raise Exception("GitHub commit create не вернул sha")

    r = requests.patch(
        ref_url,
        headers=github_headers(),
        json={"sha": new_commit_sha, "force": False},
        timeout=40,
    )
    if r.status_code >= 300:
        raise Exception(f"GitHub ref update error {r.status_code}: {r.text[:600]}")

    return {
        "commit": new_commit,
        "sha": new_commit_sha,
        "files": list(file_map.keys()),
    }

def trigger_render_deploy():
    """
    v18.2.2:
    Если Render Auto Deploy включён, GitHub commit сам запускает deploy.
    Дополнительный deploy hook в этот момент создаёт вторую очередь и может дать скачки версий.
    Поэтому hook вызывается только при явном ENV RENDER_DEPLOY_HOOK_ENABLED=1.
    """
    if not RENDER_DEPLOY_HOOK_ENABLED:
        return "Render hook не вызван: v18.2.2 защищает от двойного deploy. Если Auto Deploy включён, Render сам подхватит GitHub push."

    if not RENDER_DEPLOY_HOOK_URL:
        return "Render hook не задан; если Auto Deploy включён, Render сам подхватит GitHub push."

    r = requests.post(RENDER_DEPLOY_HOOK_URL, timeout=30)
    if r.status_code >= 300:
        raise Exception(f"Render deploy hook error {r.status_code}: {r.text[:500]}")
    return "Render deploy hook вызван."



def trigger_render_deploy_manual():
    """
    v19.4 QUICK DEPLOY BUTTON:
    ручной deploy запускается только после того, как админ нажал 🚀 Запустить деплой.
    В отличие от старого trigger_render_deploy(), здесь не нужен RENDER_DEPLOY_HOOK_ENABLED=1,
    потому что это уже явное ручное действие администратора.
    """
    if not RENDER_DEPLOY_HOOK_URL:
        raise Exception("RENDER_DEPLOY_HOOK_URL не задан в Render Environment")

    # Render deploy hook принимает POST/GET. Делаем POST, если не получилось — пробуем GET.
    try:
        r = requests.post(RENDER_DEPLOY_HOOK_URL, timeout=30)
        if r.status_code < 300:
            return "Render deploy hook вызван через POST."
        post_err = f"POST {r.status_code}: {r.text[:300]}"
    except Exception as e:
        post_err = f"POST error: {e}"

    r = requests.get(RENDER_DEPLOY_HOOK_URL, timeout=30)
    if r.status_code >= 300:
        raise Exception(f"Render deploy hook error. {post_err}; GET {r.status_code}: {r.text[:300]}")
    return "Render deploy hook вызван через GET."


