def state_status_report():
    files = [
        (RESULTS_FILE, "learning"),
        (FROZEN_RESULTS_FILE, "frozen48"),
        (PAPER_TRADES_FILE, "paper"),
        (HISTORY_FILE, "history"),
        (BACKTEST_FILE, "backtest"),
        (ADMIN_STATE_FILE, "admin_state"),
    ]
    lines = [
        "🧾 State / backup status",
        f"Версия: {BOT_VERSION}",
        f"DATA_DIR: {DATA_DIR}",
        f"GitHub storage: {'✅ включён' if github_storage_enabled() else '❌ выключен'}",
        ""
    ]
    for path, name in files:
        exists = os.path.exists(path)
        size = os.path.getsize(path) if exists else 0
        mtime = datetime.fromtimestamp(os.path.getmtime(path)).strftime("%Y-%m-%d %H:%M:%S") if exists else "нет"
        lines.append(f"• {name}: {'✅' if exists else '❌'} | {size} байт | {mtime}")
    lines.append("")
    if _STATE_RESTORE_LAST.get("time"):
        age = int(time.time() - float(_STATE_RESTORE_LAST.get("time", 0) or 0))
        lines.append(f"State restore guard: последняя проверка {age} сек назад")
        notes = _STATE_RESTORE_LAST.get("notes") or []
        if notes:
            lines.append("State restore notes:")
            for n in notes[:6]:
                lines.append(f"• {n}")
        else:
            lines.append("Восстановление: более богатой GitHub-копии не найдено / уже актуально")
        lines.append("")
    lines.append("Для полного списка: /storage. Для отправки backup-файлов: /backup. Ручное восстановление: /state_restore")
    return "\n".join(lines)


def deploy_status_report(chat_id=None):
    state = load_admin_state()
    pending = bool(state.get("pending_deploy"))
    pver = state.get("pending_deploy_version") or "нет"
    pat = float(state.get("pending_deploy_at", 0) or 0)
    age = int(time.time() - pat) if pat else 0
    last_ver = state.get("last_deploy_version") or "нет"
    last_at = float(state.get("last_deploy_at", 0) or 0)
    last_age = int(time.time() - last_at) if last_at else 0
    wait_left = int(QUICK_DEPLOY_COOLDOWN_SECONDS - (time.time() - last_at)) if last_at else 0
    if wait_left < 0:
        wait_left = 0
    lines = [
        "🚀 Deploy status",
        f"Версия бота сейчас: {BOT_VERSION}",
        f"GitHub ready: {'✅' if github_ready() else '❌'}",
        f"Render hook: {'✅ задан' if bool(RENDER_DEPLOY_HOOK_URL) else '❌ не задан'}",
        f"Pending deploy: {'✅ да' if pending else '❌ нет'}",
    ]
    if pending:
        lines.append(f"Готовая версия к деплою: {pver}")
        lines.append(f"Файл в GitHub: {state.get('pending_deploy_file', GITHUB_PATH)}")
        lines.append(f"Готово {age} сек назад")
        if wait_left > 0:
            lines.append(f"⏳ Deploy hook на cooldown: ещё {wait_left} сек.")
            lines.append("Важно: deploy этой версии ЕЩЁ НЕ запущен. После cooldown нажми 🚀 Запустить деплой ещё раз или используй Render Manual Deploy latest commit.")
        else:
            lines.append("✅ Cooldown прошёл. Действие: нажми 🚀 Запустить деплой или отправь /deploy_latest")
    lines.append(f"Последний запущенный deploy: {last_ver}")
    if last_at:
        lines.append(f"Был {last_age} сек назад")
    lines.append(f"Cooldown: {QUICK_DEPLOY_COOLDOWN_SECONDS} сек")
    lines.append("Важно: для режима ручного деплоя лучше выключить Render Auto Deploy, иначе Render может стартовать сразу после GitHub commit.")
    return "\n".join(lines)


def admin_deploy_latest(chat_id):
    if not is_admin(chat_id):
        return "⛔ Deploy доступен только ADMIN_CHAT_ID."
    state = load_admin_state()
    if not state.get("pending_deploy"):
        return (
            "ℹ️ Нет подготовленного deploy.\n"
            "Сначала отправь свежий main.py документом в Telegram. Я проверю файл, обновлю GitHub и покажу кнопку 🚀 Запустить деплой."
        )
    if not RENDER_DEPLOY_HOOK_URL:
        return (
            "⛔ RENDER_DEPLOY_HOOK_URL не задан в Render Environment.\n"
            "Один раз добавь Deploy Hook URL в переменные Render и сделай ручной deploy через сайт. Потом кнопка будет работать."
        )
    last_at = float(state.get("last_deploy_at", 0) or 0)
    wait_left = int(QUICK_DEPLOY_COOLDOWN_SECONDS - (time.time() - last_at)) if last_at else 0
    pending_version = state.get("pending_deploy_version") or "версия не указана"
    if wait_left > 0:
        # v19.6.3: deploy НЕ запускается во время cooldown. Не вводим админа в заблуждение фразой "проверь /version".
        # Pending deploy остаётся сохранённым, чтобы после cooldown можно было нажать кнопку ещё раз.
        return (
            f"⏳ Deploy НЕ запущен: Render cooldown ещё {wait_left} сек.\n"
            f"Готовая версия ждёт запуска: {pending_version}.\n\n"
            "Что делать: подожди указанное время и нажми 🚀 Запустить деплой ещё раз.\n"
            "Альтернатива: Render → Manual Deploy → Deploy latest commit.\n\n"
            "Пока /version не изменится — это нормально, новая версия ещё не запущена."
        )

    try:
        deploy_msg = trigger_render_deploy_manual()
        state["pending_deploy"] = False
        state["last_deploy_version"] = pending_version
        state["last_deploy_at"] = time.time()
        state["last_deploy_result"] = deploy_msg
        save_admin_state(state)
        try:
            sync_github_storage_now([ADMIN_STATE_FILE], max_files=1)
        except Exception:
            pass
        return (
            f"🚀 Deploy запущен.\n"
            f"Версия: {pending_version}\n"
            f"{deploy_msg}\n\n"
            "Проверь /version через 1–2 минуты."
        )
    except Exception as e:
        state["last_deploy_error"] = str(e)
        save_admin_state(state)
        return f"⛔ Deploy не запущен: {e}"

def admin_upload_lock_left(ttl=120):
    """
    v16.4:
    Локальная защита от двойной обработки main*.py.
    ВАЖНО: этот lock НЕ синхронизируется в GitHub.
    В v15.8-v16.3 синхронизация admin_upload_lock.json могла создавать лишний commit,
    запускать Render redeploy раньше загрузки main.py и обрывать обновление.
    """
    data = load_json(ADMIN_UPLOAD_LOCK_FILE)
    if not isinstance(data, dict):
        return 0, {}

    if data.get("status") != "running":
        return 0, data

    started = float(data.get("started_at", 0) or 0)
    left = int(ttl - (time.time() - started))
    if left <= 0:
        return 0, data

    return left, data

def clear_admin_upload_lock():
    try:
        if os.path.exists(ADMIN_UPLOAD_LOCK_FILE):
            os.remove(ADMIN_UPLOAD_LOCK_FILE)
    except Exception as e:
        print(f"clear admin upload lock error: {e}")

def acquire_admin_upload_lock(chat_id, filename):
    left, data = admin_upload_lock_left()
    if left > 0:
        return False, left

    data = {
        "status": "running",
        "chat_id": str(chat_id),
        "filename": str(filename or ""),
        "started_at": time.time(),
        "version": BOT_VERSION,
    }
    save_json(ADMIN_UPLOAD_LOCK_FILE, data)
    # v16.4: не отправляем lock в GitHub, чтобы не провоцировать Render redeploy до замены main.py.
    return True, 0

def release_admin_upload_lock(status="done", error=""):
    data = load_json(ADMIN_UPLOAD_LOCK_FILE)
    if not isinstance(data, dict):
        data = {}
    data["status"] = status
    data["finished_at"] = time.time()
    data["error"] = str(error or "")
    data["version"] = BOT_VERSION
    save_json(ADMIN_UPLOAD_LOCK_FILE, data)
    # v16.4: не синхронизируем lock в GitHub.

