def telegram_download_file(file_id, dest_path):
    r = requests.get(
        f"https://api.telegram.org/bot{BOT_TOKEN}/getFile",
        params={"file_id": file_id},
        timeout=30
    ).json()

    if not r.get("ok"):
        raise Exception(f"Telegram getFile error: {r}")

    file_path = r.get("result", {}).get("file_path")
    if not file_path:
        raise Exception("Telegram не вернул file_path")

    url = f"https://api.telegram.org/file/bot{BOT_TOKEN}/{file_path}"
    content = requests.get(url, timeout=60).content

    with open(dest_path, "wb") as f:
        f.write(content)

    return dest_path


def admin_document_age_seconds(msg):
    try:
        msg_date = int((msg or {}).get("date", 0) or 0)
        if msg_date <= 0:
            return 0
        return max(0, int(time.time() - msg_date))
    except Exception:
        return 0

def admin_document_upload_key(doc):
    """
    v18.2.1:
    Защита от повторной обработки одного и того же Telegram-документа после Render redeploy.
    Telegram иногда возвращает старый main.py в backlog; без такого ключа бот может снова залить
    предыдущую версию и откатиться назад.
    """
    doc = doc or {}
    filename = (doc.get("file_name") or "").strip()
    unique = (doc.get("file_unique_id") or doc.get("file_id") or "").strip()
    size = str(doc.get("file_size") or "")
    return f"{filename}|{unique}|{size}"

def load_admin_processed_uploads():
    data = load_json(ADMIN_PROCESSED_UPLOADS_FILE)
    if not isinstance(data, dict):
        data = {}
    data.setdefault("items", {})
    return data

def save_admin_processed_uploads(data):
    try:
        save_json(ADMIN_PROCESSED_UPLOADS_FILE, data)
    except Exception as e:
        print(f"save admin processed uploads error: {e}")

def admin_upload_already_processed(doc, ttl_seconds=7 * 24 * 3600):
    key = admin_document_upload_key(doc)
    if not key.strip("|"):
        return False, key
    data = load_admin_processed_uploads()
    items = data.get("items", {}) or {}
    rec = items.get(key)
    if isinstance(rec, dict):
        ts = float(rec.get("ts", 0) or 0)
        if ts and time.time() - ts < ttl_seconds:
            return True, key
    return False, key

def mark_admin_upload_processed(doc, version=""):
    key = admin_document_upload_key(doc)
    if not key.strip("|"):
        return
    data = load_admin_processed_uploads()
    items = data.get("items", {}) or {}
    # лёгкая очистка старых записей, чтобы json не рос бесконечно
    now = time.time()
    cleaned = {}
    for k, v in items.items():
        try:
            if now - float((v or {}).get("ts", 0) or 0) < 14 * 24 * 3600:
                cleaned[k] = v
        except Exception:
            pass
    cleaned[key] = {
        "ts": now,
        "version": version or "unknown",
        "filename": (doc.get("file_name") or "") if isinstance(doc, dict) else "",
        "size": (doc.get("file_size") or "") if isinstance(doc, dict) else "",
    }
    data["items"] = cleaned
    save_admin_processed_uploads(data)
    try:
        sync_github_storage_now([ADMIN_PROCESSED_UPLOADS_FILE], max_files=1)
    except Exception:
        pass

def admin_handle_document(chat_id, msg):
    if not is_admin(chat_id):
        return "⛔ Нет доступа."

    state = load_admin_state()

    doc = msg.get("document") or {}
    file_id = doc.get("file_id")
    filename = (doc.get("file_name") or "").strip() or "main.py"
    filename_l = filename.lower()

    is_main_py = filename_l.endswith(".py") and filename_l.startswith("main")
    waiting_file = bool(state.get("waiting_file"))

    # v18.2.1 ADMIN UPLOAD SAFETY:
    # Audit .txt, картинки, любые не-main*.py документы не должны даже случайно запускать deploy.
    # Особенно важно, когда админ отправляет /audit_file обратно в чат.
    direct_quick_update = bool(is_admin(chat_id) and is_main_py)

    if not waiting_file and not direct_quick_update:
        return None

    if waiting_file and not filename_l.endswith(".py"):
        # Если админ случайно включил режим обновления и отправил audit .txt — не деплоим.
        return "⛔ Это не файл обновления. Для deploy нужен свежий main.py / main*.py. Audit .txt не загружается как код."

    if not is_main_py:
        return "⛔ Для безопасности принимаю к обновлению только свежий main.py / main*.py."

    # v18.2.2: не ставим несколько deploy подряд в очередь Render.
    # Это и вызвало скачок v18.2 -> v18.1 -> v18.2 при быстрых обновлениях.
    try:
        last_deploy_at = float((state or {}).get("last_deploy_at", 0) or 0)
        wait_left = int(ADMIN_DEPLOY_MIN_INTERVAL - (time.time() - last_deploy_at))
        if last_deploy_at and wait_left > 0 and not waiting_file:
            return (
                f"⏳ Недавно уже был deploy. Чтобы Render не запускал старые версии из очереди, "
                f"новый main.py пока не принимаю. Подожди {wait_left} сек и проверь /version."
            )
    except Exception:
        pass

    age = admin_document_age_seconds(msg)
    # Старые документы после Render redeploy — главная причина внезапного отката на предыдущую версию.
    # Для quick upload жёсткий лимит 10 минут; для режима /admin_update — 30 минут.
    max_age = 1800 if waiting_file else 600
    if age > max_age:
        save_admin_state({**state, "waiting_file": False})
        return (
            f"⚠️ Старый файл обновления пропущен ({age // 60} мин назад).\n"
            "Чтобы не откатить бота на предыдущую версию, старые main.py из очереди Telegram больше не деплоятся.\n"
            "Для обновления отправь свежий main.py ещё раз."
        )

    already, upload_key = admin_upload_already_processed(doc)
    if already:
        save_admin_state({**state, "waiting_file": False})
        return (
            "⚠️ Этот файл main.py уже был обработан ранее. Повторный deploy не запускаю, "
            "чтобы бот не откатился на старую версию после Render/Telegram backlog.\n"
            "Проверь /version. Если нужно обновить код — отправь новый файл main.py."
        )

    if not file_id:
        return "Не вижу file_id у документа."

    locked, left = acquire_admin_upload_lock(chat_id, filename)
    if not locked:
        return f"⏳ Обновление уже обрабатывается. Подожди примерно {max(1, left)} сек и проверь /version."

    try:
        # v15.7: перед заменой кода принудительно фиксируем и отправляем learning JSON в GitHub.
        # Иначе при быстром deploy Render может подняться из старой копии без frozen_results,
        # и закрытые 48ч проценты снова начнут плавать.
        try:
            persist_closed_learning_freeze(sync_now=False)
        except Exception as _freeze_e:
            print(f"predeploy learning freeze sync error: {_freeze_e}")

        telegram_download_file(file_id, ADMIN_UPLOAD_FILE)

        uploaded_text = python_compile_file(ADMIN_UPLOAD_FILE)
        upload_version = extract_bot_version_from_text(uploaded_text) or "версия не найдена"

        # Защита от повторного redeploy той же версии. Это не мешает нормальному обновлению,
        # потому что каждое исправление должно получать новый BOT_VERSION.
        if upload_version == BOT_VERSION:
            mark_admin_upload_processed(doc, upload_version)
            release_admin_upload_lock("skipped_same_version")
            save_admin_state({**state, "waiting_file": False})
            return (
                f"⚠️ Файл содержит ту же версию, что уже запущена: {BOT_VERSION}.\n"
                "Deploy не запускаю, чтобы не создавать лишний Render redeploy."
            )

        current = github_get_file(GITHUB_PATH)
        backup_path = ""
        backup_status = "не создан"
        commit_sha = ""
        current_bytes = b""
        current_text = ""

        new_bytes = open(ADMIN_UPLOAD_FILE, "rb").read()
        if current:
            current_bytes, _current_meta = github_get_file_bytes(GITHUB_PATH)
            current_text = (current_bytes or b"").decode("utf-8", errors="ignore")
            if current_bytes and current_bytes == new_bytes:
                mark_admin_upload_processed(doc, upload_version)
                release_admin_upload_lock("skipped_same_content")
                save_admin_state({**state, "waiting_file": False})
                return (
                    f"⚠️ Такой же main.py уже лежит в GitHub. Версия: {upload_version}.\n"
                    "Deploy не запускаю повторно. Проверь /version."
                )

            # v19.11.8.4 LARGE FILE BACKUP FIX:
            # GitHub Contents API may return empty content for main.py >1MB.
            # Fetch raw bytes via github_get_file_bytes(), then commit backup+main.py atomically.
            if current_bytes:
                backup_path = _v191182_backup_path_for_current_main(current_text)
            else:
                backup_status = "не создан — не удалось прочитать текущий main.py из GitHub"

        if backup_path:
            atomic_result = github_put_files_atomic(
                {
                    backup_path: current_bytes,
                    GITHUB_PATH: new_bytes,
                },
                f"deploy {upload_version} with atomic backup"
            )
            commit_sha = str((atomic_result or {}).get("sha") or "")
            backup_status = f"создан\nФайл: {backup_path}"
        else:
            # Первый commit в пустой repo или current main.py не прочитан: backup создать не из чего.
            current_sha = current.get("sha") if current else None
            put_result = github_put_file(
                GITHUB_PATH,
                new_bytes,
                f"deploy {upload_version} single-main-commit",
                sha=current_sha
            )
            try:
                commit_sha = str(((put_result or {}).get("commit") or {}).get("sha") or "")
            except Exception:
                commit_sha = ""

        mark_admin_upload_processed(doc, upload_version)

        # v19.4 QUICK DEPLOY BUTTON:
        # После проверки и GitHub commit НЕ запускаем Render сразу.
        # Показываем админу одну кнопку 🚀 Запустить деплой.
        prev_state = state if isinstance(state, dict) else {}
        new_state = dict(prev_state)
        new_state.update({
            "waiting_file": False,
            "chat_id": str(chat_id),
            "last_backup_path": backup_path,
            "last_backup_status": backup_status,
            "last_backup_created_at": time.time() if backup_path else 0,
            "last_github_commit": commit_sha,
            "last_github_upload_version": upload_version,
            "last_github_upload_at": time.time(),
            "pending_deploy": True,
            "pending_deploy_version": upload_version,
            "pending_deploy_at": time.time(),
            "pending_deploy_file": GITHUB_PATH,
            "last_deploy_version": prev_state.get("last_deploy_version", ""),
            "last_deploy_at": prev_state.get("last_deploy_at", 0)
        })
        save_admin_state(new_state)
        try:
            sync_github_storage_now([ADMIN_STATE_FILE, ADMIN_PROCESSED_UPLOADS_FILE], max_files=2)
        except Exception:
            pass

        release_admin_upload_lock("done")

        return (
            (
                f"✅ main.py принят и отправлен в GitHub.\n"
                f"Версия файла: {upload_version}\n"
                f"Проверка синтаксиса: OK\n"
                f"Backup: {backup_status}\n\n"
                "Теперь нажми одну кнопку: 🚀 Запустить деплой.\n"
                "После запуска проверь /version через 1–2 минуты.\n\n"
                "Важно: для режима ручного деплоя лучше выключить Render Auto Deploy, иначе Render может начать deploy сразу после GitHub commit."
            ),
            quick_deploy_keyboard()
        )

    except Exception as e:
        release_admin_upload_lock("error", str(e))
        return f"⛔ Обновление остановлено: {e}"

def admin_rollback(chat_id):
    if not is_admin(chat_id):
        return "⛔ Нет доступа."

    if not github_ready():
        return "⛔ GitHub ENV не заполнены."

    state = load_admin_state()
    backup_path = state.get("last_backup_path")

    if not backup_path or "GitHub history" in str(backup_path):
        return "Backup отдельным файлом не создан: v18.4.2 отключил backup commit, чтобы Render не стартовал старую версию. Rollback делай через GitHub history / Render previous deploy."

    try:
        backup = github_get_file(backup_path)
        current = github_get_file(GITHUB_PATH)

        if not backup or not backup.get("content"):
            return "Backup-файл в GitHub не найден."

        backup_bytes = base64.b64decode(backup["content"])
        current_sha = current.get("sha") if current else None

        github_put_file(
            GITHUB_PATH,
            backup_bytes,
            f"rollback to {backup_path}",
            sha=current_sha
        )

        deploy_msg = trigger_render_deploy()

        return f"✅ Rollback выполнен: {backup_path}\n{deploy_msg}\nПроверь /version через 1–3 минуты."

    except Exception as e:
        return f"⛔ Rollback не выполнен: {e}"

# === v11.0 weekday statistics ===
WEEKDAY_ASSETS = ["BTC", "ETH", "SOL", "SUI", "LINK", "TAO", "NEAR", "AAVE", "BNB", "ADA", "AVAX", "INJ"]
WEEKDAY_NAMES = ["Пн", "Вт", "Ср", "Чт", "Пт", "Сб", "Вс"]

def get_daily_candles_raw(symbol):
    data = requests.get(
        "https://api.kucoin.com/api/v1/market/candles",
        params={"symbol": symbol, "type": "1day"},
        timeout=20
    ).json()

    if data.get("code") != "200000":
        raise Exception(data)

    candles = sorted(data.get("data", []), key=lambda x: int(x[0]))

    result = []
    for c in candles[-370:]:
        try:
            ts = int(c[0])
            result.append({
                "date": datetime.utcfromtimestamp(ts).strftime("%Y-%m-%d"),
                "weekday": datetime.utcfromtimestamp(ts).weekday(),
                "open": float(c[1]),
                "close": float(c[2]),
                "high": float(c[3]),
                "low": float(c[4]),
            })
        except Exception:
            continue

    return result

def update_weekday_stats():
    data = load_json(WEEKDAY_FILE)
    if not isinstance(data, dict):
        data = {}

    data.setdefault("records", {})
    data["updated_at"] = datetime.utcnow().isoformat()

    added = 0

    for asset in WEEKDAY_ASSETS:
        symbol = f"{asset}-USDT"
        try:
            candles = get_daily_candles_raw(symbol)

            # Последняя дневная свеча может быть ещё неполной, поэтому берём все кроме самой последней.
            for c in candles[:-1]:
                if c["open"] <= 0 or c["low"] <= 0:
                    continue

                key = f"{asset}:{c['date']}"

                if key in data["records"]:
                    continue

                intraday_drop = (c["low"] / c["open"] - 1) * 100
                rebound_from_low = (c["close"] / c["low"] - 1) * 100
                daily_change = (c["close"] / c["open"] - 1) * 100

                data["records"][key] = {
                    "asset": asset,
                    "date": c["date"],
                    "weekday": c["weekday"],
                    "open": c["open"],
                    "low": c["low"],
                    "high": c["high"],
                    "close": c["close"],
                    "intraday_drop": intraday_drop,
                    "rebound_from_low": rebound_from_low,
                    "daily_change": daily_change,
                }
                added += 1

            time.sleep(0.05)

        except Exception:
            continue

    save_json(WEEKDAY_FILE, data)
    return added, data

def avg(values):
    return sum(values) / len(values) if values else 0

def median_value(values):
    try:
        vals = [float(x) for x in values if isinstance(x, (int, float))]
        return statistics.median(vals) if vals else 0
    except Exception:
        return 0

def weekday_confidence(n):
    try:
        n = int(n or 0)
    except Exception:
        n = 0
    if n >= 40:
        return "уверенность высокая"
    if n >= 25:
        return "уверенность средняя"
    if n >= 14:
        return "можно учитывать осторожно"
    return "данных мало"

def weekday_report():
    added, data = update_weekday_stats()
    sync_github_storage_now([WEEKDAY_FILE, CHAT_ID_FILE, LAST_UPDATE_FILE])
    records = list((data.get("records") or {}).values())

    def asset_weekday_stats(asset):
        rows = [r for r in records if r.get("asset") == asset]
        stats = []

        for wd in range(7):
            rr = [r for r in rows if int(r.get("weekday", -1)) == wd]
            if not rr:
                continue

            drops = [r.get("intraday_drop", 0) for r in rr]
            rebounds = [r.get("rebound_from_low", 0) for r in rr]
            dailies = [r.get("daily_change", 0) for r in rr]

            stats.append({
                "wd": wd,
                "n": len(rr),
                "drop": avg(drops),
                "median_drop": median_value(drops),
                "rebound": avg(rebounds),
                "median_rebound": median_value(rebounds),
                "daily": avg(dailies),
                "prob_drop_2": sum(1 for x in drops if x <= -2.0) / len(drops) * 100 if drops else 0,
                "prob_rebound_1": sum(1 for x in rebounds if x >= 1.0) / len(rebounds) * 100 if rebounds else 0,
                "prob_green_close": sum(1 for x in dailies if x > 0) / len(dailies) * 100 if dailies else 0,
            })

        return stats

    def best_for_asset(asset):
        stats = asset_weekday_stats(asset)
        if not stats:
            return None
        return sorted(stats, key=lambda x: (x["drop"], -x["rebound"]))[0]

    def basket_recommendation(assets):
        """
        v13.4:
        Для DCA нужна не таблица по каждой монете, а один день недели для корзины.
        Считаем голосование: в какой день чаще выпадает локальный минимум у выбранных активов.
        Затем смотрим среднюю просадку/отскок по корзине.
        """
        best_by_asset = {}
        votes = {wd: 0 for wd in range(7)}
        basket_rows = {wd: [] for wd in range(7)}

        for asset in assets:
            stats = asset_weekday_stats(asset)
            if not stats:
                continue

            best = sorted(stats, key=lambda x: (x["drop"], -x["rebound"]))[0]
            best_by_asset[asset] = best
            votes[best["wd"]] += 1

            for s in stats:
                basket_rows[s["wd"]].append(s)

        candidates = []
        for wd in range(7):
            rows = basket_rows.get(wd) or []
            if not rows:
                continue

            candidates.append({
                "wd": wd,
                "votes": votes.get(wd, 0),
                "assets_n": len(rows),
                "drop": avg([r["drop"] for r in rows]),
                "rebound": avg([r["rebound"] for r in rows]),
                "daily": avg([r["daily"] for r in rows]),
            })

        if not candidates:
            return None

        # Приоритет: большинство активов, потом более глубокая средняя просадка, потом отскок.
        best_day = sorted(candidates, key=lambda x: (-x["votes"], x["drop"], -x["rebound"]))[0]
        second = sorted(candidates, key=lambda x: (x["drop"], -x["rebound"]))[0]

        return {
            "best_day": best_day,
            "best_by_asset": best_by_asset,
            "deepest_day": second,
            "candidates": candidates,
        }

    dca_assets = ["BTC", "ETH", "SOL"]
    dca = basket_recommendation(dca_assets)
    all_major = basket_recommendation(WEEKDAY_ASSETS[:12])

    # v15.0: делаем отчёт понятнее — показываем период статистики и защиту от дублей.
    dates = sorted([str(r.get("date")) for r in records if r.get("date")])
    period_line = f"Период статистики: {dates[0]} — {dates[-1]}\n" if dates else "Период статистики: данных пока нет\n"
    per_asset_counts = {}
    for r in records:
        a = r.get("asset")
        if a:
            per_asset_counts[a] = per_asset_counts.get(a, 0) + 1
    avg_per_asset = int(round(avg(list(per_asset_counts.values())))) if per_asset_counts else 0

    text = (
        f"📅 Статистика по дням недели\n"
        f"Версия: {BOT_VERSION}\n"
        f"Файл: {WEEKDAY_FILE}\n"
        f"{period_line}"
        f"Новых записей за запуск: {added}\n"
        f"Всего наблюдений: {len(records)}\n"
        f"Монет в статистике: {len(per_asset_counts)} | записей на монету в среднем: {avg_per_asset}\n"
        f"Дубли не добавляются: ключ = монета + дата закрытой дневной свечи.\n"
        f"v18.0: история расширена до ~365 закрытых дней, добавлены медианы/вероятности/confidence.\n\n"
    )

    if dca:
        best = dca["best_day"]
        deepest = dca["deepest_day"]

        text += "🎯 Итог для еженедельной DCA-покупки BTC/ETH/SOL\n"
        text += (
            f"Рекомендуемый день: {WEEKDAY_NAMES[best['wd']]} "
            f"(совпадает у {best['votes']} из {len(dca_assets)} активов)\n"
        )
        text += (
            f"Средняя просадка корзины в этот день: {best['drop']:.2f}% | "
            f"средний отскок: +{best['rebound']:.2f}% | итог дня: {best['daily']:+.2f}%\n"
        )

        if deepest["wd"] != best["wd"]:
            text += (
                f"Альтернатива по самой глубокой средней просадке: "
                f"{WEEKDAY_NAMES[deepest['wd']]} "
                f"({deepest['drop']:.2f}%, отскок +{deepest['rebound']:.2f}%).\n"
            )

        text += "Разбивка по твоей корзине:\n"

        for asset in dca_assets:
            b = dca["best_by_asset"].get(asset)
            if b:
                text += f"• {asset}: {WEEKDAY_NAMES[b['wd']]} — просадка {b['drop']:.2f}%, отскок +{b['rebound']:.2f}%\n"

        if dca["best_day"]["wd"] == 1:
            text += "Вывод: для одной покупки в неделю логичнее ставить DCA на вторник.\n"
        else:
            text += f"Вывод: для одной покупки в неделю логичнее ставить DCA на {WEEKDAY_NAMES[best['wd']]}.\n"

        text += "Если можно разделить покупку: BTC/SOL — по своему лучшему дню, ETH — по своему.\n\n"

    if all_major:
        best_all = all_major["best_day"]
        text += "🌐 День локальных минимумов по большинству основных монет\n"
        text += (
            f"Большинство сейчас указывает на: {WEEKDAY_NAMES[best_all['wd']]} "
            f"({best_all['votes']} совпадений среди основных активов).\n"
        )
        text += (
            f"Средняя просадка по рынку в этот день: {best_all['drop']:.2f}% | "
            f"средний отскок: +{best_all['rebound']:.2f}%\n\n"
        )

    text += "📌 Детально по монетам:\n\n"

    for asset in WEEKDAY_ASSETS[:12]:
        best = best_for_asset(asset)
        if not best:
            continue

        reliability = weekday_confidence(best["n"])

        text += f"{asset}: вероятный день локальных минимумов — {WEEKDAY_NAMES[best['wd']]} ({reliability})\n"
        text += (
            f"  наблюдений: {best['n']} | средняя просадка: {best['drop']:.2f}% "
            f"(медиана {best.get('median_drop', 0):.2f}%) | отскок: +{best['rebound']:.2f}% "
            f"(медиана +{best.get('median_rebound', 0):.2f}%) | итог дня: {best['daily']:+.2f}%\n"
        )
        text += (
            f"  вероятность просадки >2%: {best.get('prob_drop_2', 0):.0f}% | "
            f"отскока от минимума >1%: {best.get('prob_rebound_1', 0):.0f}% | "
            f"зелёного закрытия: {best.get('prob_green_close', 0):.0f}%\n\n"
        )

    text += (
        "Важно: это статистика наблюдений, а не команда покупать. "
        "Для DCA это помогает выбрать день недели, но учитывать нужно вместе с BTC, страхом, объёмом и текущим риском рынка."
    )

    return text

