def v188_delay_return_from_start_pcts(start_to_delay_pct, start_to_latest_pct):
    """v18.8: доходность если вход был не сразу, а в момент delay checkpoint, до последнего доступного checkpoint."""
    try:
        a = 1.0 + float(start_to_delay_pct) / 100.0
        b = 1.0 + float(start_to_latest_pct) / 100.0
        if a <= 0:
            return None
        return round((b / a - 1.0) * 100.0, 2)
    except Exception:
        return None


def v188_shadow_timing_for_rec(rec):
    """v18.8: сравнивает вход сразу с входом через 1ч/3ч/6ч/12ч по уже накопленным checkpoints.
    Ничего не покупает и не меняет веса — это только ускорение обучения.
    """
    if not isinstance(rec, dict):
        return None
    values = v18_checkpoint_values(rec)
    if len(values) < 2:
        return None
    order = ["15m", "30m", "1h", "3h", "6h", "12h", "24h", "48h"]
    idx = {name: i for i, name in enumerate(order)}
    value_map = {name: pct for name, pct in values}
    latest_name, latest_pct = max(values, key=lambda kv: idx.get(kv[0], -1))
    latest_i = idx.get(latest_name, -1)
    if latest_i <= 0:
        return None

    candidates = []
    label_map = {"1h": "1ч", "3h": "3ч", "6h": "6ч", "12h": "12ч"}
    for delay_name in ["1h", "3h", "6h", "12h"]:
        if delay_name not in value_map:
            continue
        if idx.get(delay_name, 99) >= latest_i:
            continue
        delayed_ret = v188_delay_return_from_start_pcts(value_map[delay_name], latest_pct)
        if delayed_ret is None:
            continue
        candidates.append((delay_name, label_map.get(delay_name, delay_name), delayed_ret, value_map[delay_name]))
    if not candidates:
        return None

    # лучший сценарий задержки — максимальный результат от точки задержанного входа до последнего checkpoint.
    best = max(candidates, key=lambda x: x[2])
    worst_delay = min(candidates, key=lambda x: x[2])
    asset = str(rec.get("asset", "?")).upper()
    regime = v183_regime_for_rec(rec)
    direct = float(latest_pct)
    best_name, best_label, best_ret, delay_start_pct = best

    if direct <= -3 and best_ret > direct + 2 and best_ret > -3:
        cls = "delay_better"
        note = f"{asset}: ждать {best_label} было лучше входа сразу ({best_ret:+.2f}% против {direct:+.2f}% до {latest_name})"
    elif direct <= -3 and best_ret <= -3:
        cls = "skip_best"
        note = f"{asset}: даже после задержки лучший сценарий {best_label} = {best_ret:+.2f}%, лучше полный пропуск"
    elif direct >= 3 and best_ret < direct - 2:
        cls = "entry_now_better"
        note = f"{asset}: вход сразу пока был лучше задержки ({direct:+.2f}% против {best_label} {best_ret:+.2f}%)"
    elif best_ret > direct + 1.5:
        cls = "delay_slightly_better"
        note = f"{asset}: задержка {best_label} немного улучшала вход ({best_ret:+.2f}% против {direct:+.2f}%)"
    else:
        cls = "timing_neutral"
        note = f"{asset}: тайминг пока спорный, лучший delay {best_label} {best_ret:+.2f}% против входа сразу {direct:+.2f}%"

    return {
        "asset": asset,
        "regime": regime,
        "latest": latest_name,
        "direct_pct": round(direct, 2),
        "best_delay": best_name,
        "best_delay_label": best_label,
        "best_delay_return": round(float(best_ret), 2),
        "worst_delay": worst_delay[0],
        "worst_delay_return": round(float(worst_delay[2]), 2),
        "class": cls,
        "note": note,
    }


def v188_shadow_timing_summary(data):
    """v18.8: Delayed Entry / Shadow Timing Engine для /learning_full и audit_file."""
    if not isinstance(data, dict):
        return ""
    open_items = data.get("open", {}) if isinstance(data.get("open", {}), dict) else {}
    closed = data.get("closed", []) if isinstance(data.get("closed", []), list) else []
    records = list(open_items.values()) + list(closed)
    rows = []
    for rec in records:
        r = v188_shadow_timing_for_rec(rec)
        if r:
            rows.append(r)
    if not rows:
        return (
            "⏱ v18.8 SHADOW TIMING / DELAYED ENTRY\n"
            "Пока мало checkpoints для сравнения задержки входа 1ч/3ч/6ч/12ч. Ждём новые 3ч/6ч/12ч/24ч точки.\n\n"
        )

    class_counts = {}
    delay_counts = {}
    regime_counts = {}
    for r in rows:
        class_counts[r["class"]] = class_counts.get(r["class"], 0) + 1
        delay_counts[r["best_delay_label"]] = delay_counts.get(r["best_delay_label"], 0) + 1
        regime_counts[r["regime"]] = regime_counts.get(r["regime"], 0) + 1

    def fmt_counts(d):
        return ", ".join([f"{k}:{v}" for k, v in sorted(d.items(), key=lambda kv: kv[1], reverse=True)]) or "данных мало"

    useful_wait = class_counts.get("delay_better", 0) + class_counts.get("delay_slightly_better", 0)
    skip_best = class_counts.get("skip_best", 0)
    now_better = class_counts.get("entry_now_better", 0)
    neutral = class_counts.get("timing_neutral", 0)

    # Показываем сначала самые важные уроки: полный пропуск / задержка лучше / вход сразу лучше.
    priority = {"skip_best": 0, "delay_better": 1, "delay_slightly_better": 2, "entry_now_better": 3, "timing_neutral": 4}
    examples = sorted(rows, key=lambda r: (priority.get(r["class"], 9), -abs(r.get("direct_pct", 0))))[:7]

    text = (
        "⏱ v18.8 SHADOW TIMING / DELAYED ENTRY ENGINE\n"
        "Цель: понять не только 'не покупать сейчас', а когда после запрета вход мог стать лучше: через 1ч/3ч/6ч/12ч или полный пропуск.\n"
        f"Проверено сценариев: {len(rows)} | ждать улучшало вход: {useful_wait} | полный пропуск лучше: {skip_best} | вход сразу был лучше: {now_better} | спорно: {neutral}.\n"
        f"Лучшие задержки по текущей статистике: {fmt_counts(delay_counts)}.\n"
        f"Режимы timing-проверок: {fmt_counts(regime_counts)}.\n"
        "Правило безопасности: это shadow-обучение, реальные веса и автоторговля не меняются.\n"
    )
    if examples:
        text += "Ключевые timing-кейсы:\n" + "\n".join(["• " + r["note"] for r in examples]) + "\n"
    return text + "\n"


def v190_coin_timing_profile(data):
    """v19.0: Coin Timing + Avoid-Pump Profile для learning_full/audit_file."""
    if not isinstance(data, dict):
        return ""
    open_items = data.get("open", {}) if isinstance(data.get("open", {}), dict) else {}
    closed = data.get("closed", []) if isinstance(data.get("closed", []), list) else []
    records = list(open_items.values()) + list(closed)
    rows = []
    for rec in records:
        try:
            r = v188_shadow_timing_for_rec(rec)
            if r:
                rows.append(r)
        except Exception:
            pass
    if not rows:
        return "🧭 v19.0 Coin Timing Profile\nПока мало timing-точек для профиля монет.\n\n"
    by_asset = {}
    by_regime = {}
    delay_counts = {}
    for r in rows:
        asset = str(r.get("asset", "?")).upper()
        regime = str(r.get("regime", "unknown"))
        cls = str(r.get("class", ""))
        delay = str(r.get("best_delay_label", "?"))
        delay_counts[delay] = delay_counts.get(delay, 0) + 1
        by_regime.setdefault(regime, {"wait":0,"skip":0,"now":0,"neutral":0})
        by_asset.setdefault(asset, {"wait":0,"skip":0,"now":0,"neutral":0})
        if cls in ["delay_better", "delay_slightly_better"]:
            key="wait"
        elif cls == "skip_best":
            key="skip"
        elif cls == "entry_now_better":
            key="now"
        else:
            key="neutral"
        by_asset[asset][key]+=1
        by_regime[regime][key]+=1
    def fmt(d):
        return ", ".join([f"{k}:{v}" for k,v in sorted(d.items(), key=lambda kv: kv[1], reverse=True)]) or "мало данных"
    wait_assets = [(a,s) for a,s in sorted(by_asset.items(), key=lambda kv: (kv[1]['wait'], -kv[1]['skip']), reverse=True) if s['wait']>0][:5]
    skip_assets = [(a,s) for a,s in sorted(by_asset.items(), key=lambda kv: (kv[1]['skip'], -kv[1]['wait']), reverse=True) if s['skip']>0][:5]
    try:
        p = paper_store()
        pclosed = p.get("closed", []) if isinstance(p.get("closed", []), list) else []
    except Exception:
        pclosed=[]
    avoid_saved=avoid_pump=avoid_neutral=0
    paper_examples=[]
    for t in pclosed:
        if not isinstance(t, dict) or str(t.get("virtual_type", "")) != "AVOID_PUMP_TEST":
            continue
        out=paper_outcome(t)
        r48=(t.get("results",{}) or {}).get("48h")
        if out=="avoid_saved": avoid_saved+=1
        elif out=="pump_continued_no_pullback": avoid_pump+=1
        elif out=="avoid_neutral": avoid_neutral+=1
        if isinstance(r48,(int,float)) and len(paper_examples)<6:
            paper_examples.append(f"• {str(t.get('asset','?')).upper()}: {paper_outcome_label(out)} | 48ч {r48:+.2f}%")
    regime_txt = "; ".join([f"{r}: ждать {s['wait']} / skip {s['skip']} / сразу {s['now']}" for r,s in sorted(by_regime.items(), key=lambda kv: kv[1]['wait']+kv[1]['skip'], reverse=True)[:5]])
    text=(
        "🧭 v19.0 Coin Timing / Avoid-Pump Profile\n"
        "Цель: разделить, где лучше ждать 1ч/3ч/6ч/12ч, а где безопаснее полный skip. Это обучение, не автоторговля.\n"
        f"Timing: всего {len(rows)} | лучшие задержки: {fmt(delay_counts)}.\n"
        f"Режимы: {regime_txt or 'мало данных'}.\n"
    )
    if wait_assets:
        text += "Монеты, где чаще помогает ожидание:\n" + "\n".join([f"• {a}: ждать {s['wait']} / skip {s['skip']} / сразу {s['now']}" for a,s in wait_assets]) + "\n"
    if skip_assets:
        text += "Монеты/кейсы, где чаще лучше полный skip:\n" + "\n".join([f"• {a}: skip {s['skip']} / ждать {s['wait']}" for a,s in skip_assets]) + "\n"
    text += f"Avoid-Pump Paper: 🛡 не догонять спасло {avoid_saved} | 📈 памп продолжился {avoid_pump} | 🟡 нейтрально {avoid_neutral}.\n"
    if paper_examples:
        text += "Последние Avoid-Pump уроки:\n" + "\n".join(paper_examples[-6:]) + "\n"
    text += "Правило v19.0: 📈 памп продолжился ≠ BUY-ошибка; он идёт в timing/avoid-pump профиль, а не включает автопокупку. Вход сразу пока не усиливается.\n\n"
    return text


def v192_checkpoint_accelerator_summary(data, compact=False):
    """v19.2: ускоряет самообучение без ожидания 48ч.
    Использует уже накопленные 6ч/12ч/24ч checkpoints как предварительную статистику.
    Не включает автоторговлю и не меняет реальные веса агрессивно.
    """
    if not isinstance(data, dict):
        return "⚡ v19.2 Checkpoint Accelerator\nДанных обучения пока нет.\n"
    open_items = data.get("open", {}) if isinstance(data.get("open", {}), dict) else {}
    rows = []
    mature = 0
    for rec in open_items.values():
        if not isinstance(rec, dict):
            continue
        vals = v18_checkpoint_values(rec)
        if not vals:
            continue
        asset = str(rec.get("asset", "?")).upper()
        verdict = str(rec.get("verdict", "") or "")
        regime = v183_regime_for_rec(rec)
        latest_name, latest = vals[-1]
        best_name, best = max(vals, key=lambda kv: kv[1])
        worst_name, worst = min(vals, key=lambda kv: kv[1])
        if latest_name in ["6h", "12h", "24h", "48h"]:
            mature += 1
        is_pump = ("НЕ ДОГОНЯТЬ" in verdict) or ("СПЕКУЛЯТИВ" in verdict)
        is_quality = asset in QUALITY_LEARNING_ASSETS or asset in ["BTC", "ETH", "SOL", "LINK", "AAVE", "BNB", "TAO", "SUI", "AVAX", "NEAR"]
        if worst <= -8:
            bucket = "skip"
            note = f"{asset}: полный skip/не вход подтверждается, худший {worst_name} {worst:+.2f}%"
        elif best >= 8 and is_pump:
            bucket = "pump"
            note = f"{asset}: памп продолжился, нужен timing-профиль, лучший {best_name} {best:+.2f}%"
        elif best >= 6 and is_quality:
            bucket = "quality"
            note = f"{asset}: качественный актив растёт против фона, проверить задержку/условия, лучший {best_name} {best:+.2f}%"
        elif latest <= -4:
            bucket = "protect"
            note = f"{asset}: осторожность пока защищает, последний {latest_name} {latest:+.2f}%"
        else:
            bucket = "neutral"
            note = f"{asset}: пока спорно/нейтрально, последний {latest_name} {latest:+.2f}%"
        rows.append({"asset":asset,"bucket":bucket,"regime":regime,"latest_name":latest_name,"latest":latest,"best":best,"worst":worst,"note":note})
    counts = {"skip":0,"pump":0,"quality":0,"protect":0,"neutral":0}
    for r in rows:
        counts[r["bucket"]] = counts.get(r["bucket"],0)+1
    # Сначала важные защитные и спорные кейсы, затем quality/pump.
    pr = {"skip":0,"protect":1,"quality":2,"pump":3,"neutral":4}
    examples = sorted(rows, key=lambda r: (pr.get(r["bucket"],9), -abs(float(r.get("best",0) or 0)), -abs(float(r.get("worst",0) or 0))))[:8]
    if compact:
        return (
            f"⚡ Learning Sprint\n"
            f"Не ждём 48ч: уже используем 6/12/24ч checkpoints.\n"
            f"Open с checkpoints: {len(rows)} | зрелых 6ч+: {mature}\n"
            f"Skip/защита: {counts.get('skip',0)+counts.get('protect',0)} | quality-growth: {counts.get('quality',0)} | pump-growth: {counts.get('pump',0)} | спорно: {counts.get('neutral',0)}\n"
            f"Вход сразу по-прежнему не усиливаем. Подробно: /audit_file"
        )
    text = (
        "⚡ v19.6 CHECKPOINT ACCELERATOR / LEARNING SPRINT\n"
        "Задача: не сидеть 48ч без дела. 48ч остаётся финальным судом, но 6ч/12ч/24ч уже дают предварительные уроки для профилей монет и режимов. Автоторговля выключена.\n"
        f"Open-наблюдений с checkpoints: {len(rows)} | зрелых 6ч+: {mature}.\n"
        f"Предварительно: полный skip/не вход {counts.get('skip',0)} | осторожность защищает {counts.get('protect',0)} | quality-growth {counts.get('quality',0)} | pump-growth {counts.get('pump',0)} | спорно {counts.get('neutral',0)}.\n"
        "Что бот может делать уже сейчас: обновлять Coin Timing/Avoid-Pump профили, отмечать full-skip монеты, выделять quality-exception кейсы и не повышать BUY до финальных 48ч.\n"
    )
    if examples:
        text += "Ключевые ускоренные уроки:\n" + "\n".join(["• "+r["note"] for r in examples]) + "\n"
    text += "Правило v19.6: ранние checkpoints ускоряют обучение и строят профили, но не дают права на реальный вход без подтверждения объёма, фона и 48ч статистики.\n\n"
    return text


def v195_active_learning_profiles(data):
    """v19.5: активные профили обучения по 6/12/24ч без ожидания 48ч.
    Ничего не покупает, не включает автоторговлю и не повышает реальные BUY-веса.
    Цель — заранее подготовить качественные профили для финальной проверки после 48ч.
    """
    if not isinstance(data, dict):
        return "🧠 v19.5 ACTIVE LEARNING PROFILES\nДанных обучения пока нет.\n"
    open_items = data.get("open", {}) if isinstance(data.get("open", {}), dict) else {}
    quality = []
    full_skip = []
    avoid_pump = []
    wait_cases = []
    closing_soon = []
    now = time.time()
    for rec in open_items.values():
        if not isinstance(rec, dict):
            continue
        vals = v18_checkpoint_values(rec)
        if not vals:
            continue
        asset = str(rec.get("asset", "?")).upper()
        verdict = str(rec.get("verdict", "") or "")
        status = str(rec.get("status", "") or "")
        action = str(rec.get("action", "") or "")
        regime = v183_regime_for_rec(rec)
        best_name, best = max(vals, key=lambda kv: kv[1])
        worst_name, worst = min(vals, key=lambda kv: kv[1])
        latest_name, latest = vals[-1]
        is_pump = ("НЕ ДОГОНЯТЬ" in verdict) or ("СПЕКУЛЯТИВ" in verdict) or ("НЕ ДОГОНЯТЬ" in status) or ("СПЕКУЛЯТИВ" in status)
        is_quality = asset in QUALITY_LEARNING_ASSETS or asset in ["BTC", "ETH", "SOL", "LINK", "AAVE", "BNB", "TAO", "SUI", "AVAX", "NEAR"]
        age = float(rec.get("time", rec.get("created_at", now)) or now)
        remain_h = 48.0 - max(0.0, (now - age) / 3600.0)
        if remain_h <= 12 and remain_h > -2:
            closing_soon.append((remain_h, asset, best_name, best, worst_name, worst, regime))
        if is_quality and best >= 6 and action != "BUY":
            quality.append((best, asset, best_name, regime, latest_name, latest, worst_name, worst))
        if worst <= -8 and latest <= 0:
            full_skip.append((worst, asset, worst_name, regime, latest_name, latest))
        elif worst <= -12:
            full_skip.append((worst, asset, worst_name, regime, latest_name, latest))
        if is_pump and best >= 8:
            avoid_pump.append((best, asset, best_name, regime, latest_name, latest, worst_name, worst))
        if best >= 4 and worst < -4 and action != "BUY":
            wait_cases.append((best - worst, asset, best_name, best, worst_name, worst, regime))
    quality = sorted(quality, reverse=True)[:5]
    full_skip = sorted(full_skip, key=lambda x: x[0])[:8]
    avoid_pump = sorted(avoid_pump, reverse=True)[:5]
    wait_cases = sorted(wait_cases, reverse=True)[:5]
    closing_soon = sorted(closing_soon, key=lambda x: x[0])[:8]
    lines = [
        "🧠 ACTIVE LEARNING PROFILES CORE",
        "Задача: не ждать пассивно 48ч, а заранее раскладывать открытые наблюдения по профилям. Это НЕ автоторговля и НЕ повышение BUY-весов.",
        f"Open-наблюдений с checkpoints: {len([r for r in open_items.values() if isinstance(r, dict) and v18_checkpoint_values(r)])}",
        f"Профили сейчас: quality-exception {len(quality)} | full-skip {len(full_skip)} | avoid-pump continuation {len(avoid_pump)} | timing-spread {len(wait_cases)}",
    ]
    if quality:
        lines.append("\n🟢 Quality-exception кандидаты для проверки после 48ч:")
        for best, asset, bn, regime, ln, latest, wn, worst in quality:
            lines.append(f"• {asset}: лучший {bn} {best:+.2f}% при режиме {regime}; вход не разрешать до 48ч/объёма/фона; последний {ln} {latest:+.2f}%, худший {wn} {worst:+.2f}%")
    if full_skip:
        lines.append("\n🛡 Full-skip профиль усиливается:")
        for worst, asset, wn, regime, ln, latest in full_skip:
            lines.append(f"• {asset}: худший {wn} {worst:+.2f}% | режим {regime} | последний {ln} {latest:+.2f}% — не догонять/не усреднять")
    if avoid_pump:
        lines.append("\n📈 Avoid-pump continuation профиль:")
        for best, asset, bn, regime, ln, latest, wn, worst in avoid_pump:
            if worst < 0:
                risk_part = f"просадка {wn} {worst:+.2f}%"
            else:
                risk_part = f"минимальный откат/пока без просадки: {wn} {worst:+.2f}%"
            lines.append(f"• {asset}: памп мог продолжиться {bn} {best:+.2f}%, но {risk_part}; это timing-урок, не BUY-ошибка")
    if wait_cases:
        lines.append("\n⏱ Timing-spread кейсы:")
        for spread, asset, bn, best, wn, worst, regime in wait_cases:
            lines.append(f"• {asset}: разброс {spread:.2f} п.п. между {bn} {best:+.2f}% и {wn} {worst:+.2f}% | режим {regime}; важнее точка входа, чем вход сразу")
    if closing_soon:
        lines.append("\n⏳ Ближайшие 48ч закрытия:")
        for remain_h, asset, bn, best, wn, worst, regime in closing_soon:
            lines.append(f"• {asset}: около {max(0, remain_h):.1f}ч до финала | лучший {bn} {best:+.2f}% | худший {wn} {worst:+.2f}% | режим {regime}")
    lines.append("\nПравило v19.7.4: ранние профили готовят выводы заранее, но реальные веса/BUY/автоторговля не усиливаются без серии закрытых 48ч и улучшения рынка.")
    return "\n".join(lines) + "\n"



def v196_price_freshness(rec, now=None):
    """v19.6: возраст последнего ценового снимка для защиты обучения от устаревших данных."""
    if now is None:
        now = time.time()
    try:
        price, ts, source = learning_cached_price_for_report(rec)
        ts = float(ts or 0)
        if ts <= 0:
            return None, source or "none", 999999.0
        age_min = max(0.0, (float(now) - ts) / 60.0)
        return price, source or "cache", age_min
    except Exception:
        return None, "error", 999999.0


def v196_freshness_guard_summary(data):
    """v19.6: показывает, какие open-наблюдения свежие, а какие нельзя использовать для сильных выводов."""
    if not isinstance(data, dict):
        return "🧊 v19.6 Freshness Guard\nДанных обучения пока нет.\n"
    open_items = data.get("open", {}) if isinstance(data.get("open", {}), dict) else {}
    now = time.time()
    fresh = []
    warm = []
    stale = []
    no_data = []
    for rec in open_items.values():
        if not isinstance(rec, dict):
            continue
        asset = str(rec.get("asset", "?")).upper()
        price, source, age_min = v196_price_freshness(rec, now=now)
        vals = v18_checkpoint_values(rec)
        remain_h = None
        try:
            start_time = float(rec.get("time", rec.get("created_at", 0)) or 0)
            if start_time > 0:
                remain_h = 48.0 - max(0.0, (now - start_time) / 3600.0)
        except Exception:
            remain_h = None
        row = {"asset": asset, "age": age_min, "source": source, "price": price, "checkpoints": len(vals), "remain_h": remain_h}
        if age_min >= 999999:
            no_data.append(row)
        elif age_min <= 60:
            fresh.append(row)
        elif age_min <= 180:
            warm.append(row)
        else:
            stale.append(row)
    stale_sorted = sorted(stale + no_data, key=lambda r: r.get("age", 999999), reverse=True)[:8]
    lines = [
        "🧊 v19.6 FRESHNESS GUARD",
        "Задача: не давать боту делать сильные выводы по старым ценовым снимкам.",
        f"Open-наблюдений: {len(open_items)} | свежие ≤60м: {len(fresh)} | 60–180м: {len(warm)} | старые >180м/нет цены: {len(stale) + len(no_data)}",
    ]
    if stale_sorted:
        lines.append("\n⚠️ Не использовать для сильных выводов без обновления цены:")
        for r in stale_sorted:
            if r.get("age", 999999) >= 999999:
                age_txt = "нет свежего снимка"
            else:
                age_txt = f"снимок {int(r['age'])}м назад"
            cp = r.get("checkpoints", 0)
            remain = r.get("remain_h")
            remain_txt = f" | 48ч через {max(0, remain):.1f}ч" if isinstance(remain, (int, float)) else ""
            lines.append(f"• {r['asset']}: {age_txt}, checkpoints {cp}{remain_txt} — вывод только предварительный")
    else:
        lines.append("\n✅ Критично устаревших open-наблюдений не видно.")
    lines.append("\nПравило v19.6: если snapshot старше 60м — не усиливать BUY/Timing; старше 180м — требовать обновления цены перед сильным выводом.")
    return "\n".join(lines) + "\n"


def v196_48h_finalizer_queue(data, max_rows=12):
    """v19.6: очередь ближайших 48ч финалов, чтобы заранее видеть, какие уроки скоро закроются."""
    if not isinstance(data, dict):
        return "⏳ v19.6 48H FINALIZER\nДанных обучения пока нет.\n"
    open_items = data.get("open", {}) if isinstance(data.get("open", {}), dict) else {}
    now = time.time()
    rows = []
    for rec in open_items.values():
        if not isinstance(rec, dict):
            continue
        vals = v18_checkpoint_values(rec)
        if not vals:
            continue
        asset = str(rec.get("asset", "?")).upper()
        try:
            start_time = float(rec.get("time", rec.get("created_at", 0)) or 0)
        except Exception:
            start_time = 0
        if start_time <= 0:
            continue
        age_h = max(0.0, (now - start_time) / 3600.0)
        remain_h = 48.0 - age_h
        if remain_h > 12 or remain_h < -4:
            continue
        best_name, best = max(vals, key=lambda kv: kv[1])
        worst_name, worst = min(vals, key=lambda kv: kv[1])
        latest_name, latest = vals[-1]
        cls, note = v18_learning_decision_class(rec, final_only=False)
        regime = v183_regime_for_rec(rec)
        price, source, age_min = v196_price_freshness(rec, now=now)
        rows.append({
            "asset": asset, "remain_h": remain_h, "best_name": best_name, "best": best,
            "worst_name": worst_name, "worst": worst, "latest_name": latest_name, "latest": latest,
            "class": cls, "note": note, "regime": regime, "age_min": age_min
        })
    rows = sorted(rows, key=lambda r: abs(r["remain_h"]))[:max_rows]
    lines = [
        "⏳ v19.6 48H FINALIZER QUEUE",
        "Задача: заранее готовить финальные уроки, а не вспоминать о них после закрытия.",
        f"К закрытию/финалу в ближайшие 12ч: {len(rows)}",
    ]
    if rows:
        for r in rows:
            if r["remain_h"] >= 0:
                ttxt = f"через {r['remain_h']:.1f}ч"
            else:
                ttxt = f"просрочено {abs(r['remain_h']):.1f}ч"
            fresh_flag = "⚠️ old price" if r.get("age_min", 0) > 180 else "✅ fresh" if r.get("age_min", 999) <= 60 else "🟡 cache"
            lines.append(
                f"• {r['asset']}: финал {ttxt} | {fresh_flag} | лучший {r['best_name']} {r['best']:+.2f}% | худший {r['worst_name']} {r['worst']:+.2f}% | сейчас {r['latest_name']} {r['latest']:+.2f}% | {r['regime']}"
            )
    lines.append("\nПравило v19.6: после 48ч закрытия бот классифицирует кейс как full-skip / quality-exception / avoid-pump / neutral и только потом готовит веса, без автоторговли.")
    return "\n".join(lines) + "\n"


def v196_anti_overfit_guard(data):
    """v19.6: защита от переобучения на одном удачном входе/пампе."""
    if not isinstance(data, dict):
        return "🧯 v19.6 Anti-Overfit Guard\nДанных обучения пока нет.\n"
    open_items = data.get("open", {}) if isinstance(data.get("open", {}), dict) else {}
    closed = data.get("closed", []) if isinstance(data.get("closed", []), list) else []
    rows = []
    for rec in list(open_items.values()) + list(closed):
        if not isinstance(rec, dict):
            continue
        try:
            r = v188_shadow_timing_for_rec(rec)
            if r:
                rows.append(r)
        except Exception:
            pass
    now_better = [r for r in rows if r.get("class") == "entry_now_better"]
    wait_better = [r for r in rows if r.get("class") in ["delay_better", "delay_slightly_better"]]
    skip_best = [r for r in rows if r.get("class") == "skip_best"]
    lines = [
        "🧯 v19.6 ANTI-OVERFIT GUARD",
        "Задача: не дать одному удачному пампу сломать осторожную стратегию.",
        f"Timing-сценариев: {len(rows)} | ждать лучше {len(wait_better)} | полный skip лучше {len(skip_best)} | вход сразу лучше {len(now_better)}",
    ]
    if len(now_better) < 5:
        lines.append(f"\n🛡 Вход сразу НЕ усиливать: кейсов всего {len(now_better)} из минимум 5–10 нужных.")
    else:
        lines.append("\n🟡 Есть серия входов сразу, но всё равно требуется проверка режима рынка, объёма и 48ч закрытий.")
    if now_better:
        lines.append("Единичные now-бetter кейсы учитывать как research, не как сигнал BUY:")
        for r in now_better[-5:]:
            asset = str(r.get("asset", "?")).upper()
            regime = str(r.get("regime", "?"))
            delay = str(r.get("best_delay_label", "?"))
            lines.append(f"• {asset}: режим {regime}, лучший сценарий {delay}; веса не менять без серии")
    lines.append("\nПравило v19.6: любые BUY/entry-now усиления только после серии закрытых 48ч кейсов, а не по одному исключению.")
    return "\n".join(lines) + "\n"


def v196_learning_priority_radar(data):
    """v19.6: автопредложение следующих улучшений, чтобы ChatGPT/админ не напоминали вручную."""
    if not isinstance(data, dict):
        return "🧭 Learning Priority Radar Core\nДанных обучения пока нет.\n"
    open_items = data.get("open", {}) if isinstance(data.get("open", {}), dict) else {}
    now = time.time()
    stale_n = 0
    close_n = 0
    quality_n = 0
    full_skip_n = 0
    pump_n = 0
    for rec in open_items.values():
        if not isinstance(rec, dict):
            continue
        asset = str(rec.get("asset", "?")).upper()
        vals = v18_checkpoint_values(rec)
        if not vals:
            continue
        price, source, age_min = v196_price_freshness(rec, now=now)
        if age_min > 180:
            stale_n += 1
        try:
            start_time = float(rec.get("time", rec.get("created_at", 0)) or 0)
            remain_h = 48.0 - max(0.0, (now - start_time) / 3600.0)
            if -1 <= remain_h <= 4:
                close_n += 1
        except Exception:
            pass
        best_name, best = max(vals, key=lambda kv: kv[1])
        worst_name, worst = min(vals, key=lambda kv: kv[1])
        verdict = str(rec.get("verdict", "") or "") + " " + str(rec.get("status", "") or "")
        is_quality = asset in QUALITY_LEARNING_ASSETS or asset in ["BTC", "ETH", "SOL", "LINK", "AAVE", "BNB", "TAO", "SUI", "AVAX", "NEAR"]
        is_pump = ("НЕ ДОГОНЯТЬ" in verdict) or ("СПЕКУЛЯТИВ" in verdict)
        if is_quality and best >= 6:
            quality_n += 1
        if worst <= -8:
            full_skip_n += 1
        if is_pump and best >= 8:
            pump_n += 1
    lines = [
        "🧭 LEARNING PRIORITY RADAR CORE",
        "Авто-предложения следующих улучшений после каждого теста:",
    ]
    priorities = []
    if stale_n:
        priorities.append((1, f"Freshness guard: обновить/пометить старые цены в {stale_n} open-наблюдениях"))
    if close_n:
        priorities.append((2, f"48h finalizer: обработать {close_n} ближайших финальных закрытий"))
    if quality_n:
        priorities.append((3, f"Quality-exception: отдельно вести {quality_n} качественных ростов против плохого рынка"))
    if full_skip_n:
        priorities.append((4, f"Full-skip profile: усилить шаблоны не-догонять по {full_skip_n} просадочным кейсам"))
    if pump_n:
        priorities.append((5, f"Avoid-pump timing: разделить памп-продолжение и опасное догоняние по {pump_n} кейсам"))
    if not priorities:
        priorities.append((9, "Критичных улучшений сейчас нет: собирать статистику и ждать закрытия 48ч"))
    for _, txt in sorted(priorities)[:6]:
        lines.append(f"• {txt}")
    lines.append("\nПравило работы дальше: сделали версию → проверили → если зелёно, следующий шаг предлагает сам Radar.")
    return "\n".join(lines) + "\n"


