def build_audit_file(chat_id):
    # v18.4.1: audit_file должен ВСЕГДА либо отправить txt, либо объяснить ошибку.
    # Каждая тяжёлая секция имеет таймаут, чтобы один зависший API-запрос не ломал весь отчёт.
    ts = datetime.now().strftime("%Y%m%d_%H%M%S")
    path = f"/tmp/alex_edge_audit_{ts}.txt"
    sections = []
    def add(title, func, timeout_sec=25):
        body = audit_section_text(func, timeout_sec=timeout_sec)
        sections.append("\n" + "="*80 + f"\n{title}\n" + "="*80 + "\n" + body)

    add("VERSION", lambda: f"BOT_VERSION: {BOT_VERSION}", 5)
    add("AUDIT SHORT", audit_short_report, 15)
    add("PAPER FULL", paper_report, 12)
    add("SIGNAL FULL", unified_signal_report, 35)
    add("LEARNING FULL", lambda: learning_report(sync_github=False, full=True), 25)
    add("LEARNING QUALITY CORE", lambda: v190_coin_timing_profile(load_json(RESULTS_FILE)) + v184_learning_quality_summary(load_json(RESULTS_FILE)), 10)
    add("ACTIVE LEARNING PROFILES CORE", lambda: v195_active_learning_profiles(load_json(RESULTS_FILE)), 10)
    add("LEARNING DEVELOPMENT RADAR CORE", lambda: v196_learning_development_radar(load_json(RESULTS_FILE)), 12)
    add("PAPER CLASSIFIER V19.8", lambda: v197_closed_paper_classifier_report(), 10)
    add("ACCURACY SCORE V19.8", v198_accuracy_score_report, 10)
    add("USER STATUS V19.8", v198_user_status_report, 10)
    add("LEARNING SPRINT CORE", lambda: v192_checkpoint_accelerator_summary(load_json(RESULTS_FILE), compact=False), 10)
    add("ALERTS FULL", lambda: get_fast_pumps()[0] or "Нет alerts", 25)
    add("MARKET", market_status, 10)
    add("BTC FULL", lambda: single_analysis_full("BTC-USDT"), 25)
    add("SOL FULL", lambda: single_analysis_full("SOL-USDT"), 25)
    add("ETH FULL", lambda: single_analysis_full("ETH-USDT"), 25)

    content = "ALEX EDGE ULTRA TECH AUDIT FILE\n" + "\n".join(sections)
    try:
        with open(path, "w", encoding="utf-8") as f:
            f.write(content)
    except Exception as e:
        send_message(chat_id, f"❌ Не удалось создать audit txt: {e}")
        return None

    # v19.3.1: полный аудит никогда не отправляем длинным текстом в чат.
    # Только txt-документ; если Telegram не принял файл — короткая ошибка + audit_short.
    ok = send_document(chat_id, path, caption="🧾 Технический отчёт готов. Полный текст — только в txt-файле.")
    if not ok:
        send_message(chat_id, "⚠️ Полный audit_file собран, но Telegram не принял txt-документ. Длинный текст в чат не отправляю. Ниже только короткий аудит.")
        send_message(chat_id, audit_short_report())
    return path

def market_status():
    ctx = market_context()
    level = ctx.get("risk_level", "neutral")

    # v19.7.4: user-facing market status must keep the unified extreme-fear/no-buy wording.
    # Danger remains for non-extreme-fear cases only, so reports do not flicker between labels.
    if v195_extreme_fear_user_no_buy(ctx) or v115_extreme_fear_btc_weak(ctx):
        status = "🟡 EXTREME-FEAR / NO-BUY"
    elif level == "danger":
        status = "🔴 ОПАСНЫЙ РЫНОК"
    elif v106_safe_caution(ctx):
        status = "🟠 SAFE-CAUTION / ЖДАТЬ BTC"
    elif level == "caution" and ctx.get("macro_mod", ctx.get("geo_mod", 0)) <= -15 and ctx.get("btc_change", 0) >= 0:
        status = "🟠 ПОВЫШЕННАЯ ОСТОРОЖНОСТЬ"
    elif level == "caution":
        status = "🟡 ОСТОРОЖНО"
    elif level == "positive":
        status = "🟢 ФОН ПОМОГАЕТ"
    else:
        status = "🟡 НЕЙТРАЛЬНО"

    btc_change = ctx.get("btc_change", 0)
    fg_value = ctx.get("fg_value", 50)

    text = (
        f"🌍 Рынок\n"
        f"Версия: {BOT_VERSION}\n\n"
        f"Статус: {status}\n"
        f"BTC 24ч: {btc_change:.2f}% — {ctx.get('btc_text', 'н/д')}\n"
        f"Страх/жадность: {fg_value} — {ctx.get('fg_text', 'н/д')}\n"
    )

    if ctx.get("dom_text"):
        text += f"Dominance: {ctx['dom_text']}\n"

    text += (
        f"Новости: {compact_news_line(ctx)}\n\n"
        f"{macro_action_hint(ctx)}\n\n"
        f"Что ждём для улучшения:\n"
    )

    for item in market_improvement_plan(ctx):
        text += f"• {item}\n"

    return text.strip()

