def auto_audit_load_state():
    """v18.9: persistent state for Telegram self-check scheduler."""
    state = load_json(AUTO_AUDIT_STATE_FILE)
    if not isinstance(state, dict):
        state = {}
    state.setdefault("enabled", bool(AUTO_AUDIT_ENABLED_DEFAULT))
    state.setdefault("last_check_at", 0)
    state.setdefault("last_sent_at", 0)
    state.setdefault("last_forced_at", 0)
    state.setdefault("last_paper_closed", None)
    state.setdefault("last_paper_saved", None)
    state.setdefault("last_paper_open", None)
    state.setdefault("last_learning_open", None)
    state.setdefault("last_learning_closed", None)
    state.setdefault("last_risk", None)
    state.setdefault("last_btc_bucket", None)
    state.setdefault("last_timing_checked", None)
    state.setdefault("mode", "critical-only")
    return state



def auto_audit_effective_settings(state):
    mode = str((state or {}).get("mode", "critical-only") or "critical-only").lower().replace("_", "-")
    if mode in ["test", "hourly"]: mode = "active"
    if mode in ["critical"]: mode = "critical-only"
    if mode not in ["active", "normal", "quiet", "critical-only"]: mode = "critical-only"
    settings = {"active": (60,60,False), "normal": (180,180,False), "quiet": (360,360,False), "critical-only": (60,30,True)}
    interval_min, min_gap_min, critical_only = settings[mode]
    return mode, interval_min, min_gap_min, critical_only


def auto_audit_mode_label(mode):
    mode = str(mode or "critical-only").lower().replace("_", "-")
    labels = {"active":"active/test — раз в 60 минут", "normal":"normal — раз в 3 часа", "quiet":"quiet — раз в 6 часов", "critical-only":"critical-only — только важные события / без hourly spam"}
    return labels.get(mode, labels["critical-only"])


def auto_audit_set_mode(mode):
    mode = str(mode or "").lower().strip().replace("_", "-")
    if mode in ["test", "hourly"]: mode = "active"
    if mode in ["critical"]: mode = "critical-only"
    if mode not in ["active", "normal", "quiet", "critical-only"]:
        return None
    state = auto_audit_load_state()
    state["mode"] = mode
    state["updated_at"] = time.time()
    auto_audit_save_state(state, sync=True)
    return state


def auto_audit_mode_help():
    state = auto_audit_load_state()
    mode, interval_min, min_gap_min, critical_only = auto_audit_effective_settings(state)
    return (
        f"🧠 Auto-Audit mode\nВерсия: {BOT_VERSION}\n\n"
        f"Текущий режим: {auto_audit_mode_label(mode)}\n"
        f"Интервал проверки: {interval_min} мин\n"
        f"Минимальный gap отправки: {min_gap_min} мин\n"
        f"Critical-only: {'да' if critical_only else 'нет'}\n\n"
        "Команды:\n/auto_audit_mode critical — по умолчанию, только важные события\n/auto_audit_mode active — активный тест, раз в час\n/auto_audit_mode normal — обычный режим, раз в 3 часа\n/auto_audit_mode quiet — тихий режим, раз в 6 часов"
    )


def auto_audit_save_state(state, sync=False):
    if not isinstance(state, dict):
        return
    state["version"] = BOT_VERSION
    save_json(AUTO_AUDIT_STATE_FILE, state)
    if sync:
        background_github_sync([AUTO_AUDIT_STATE_FILE, CHAT_ID_FILE, LAST_UPDATE_FILE], max_files=3)
    else:
        mark_github_dirty(AUTO_AUDIT_STATE_FILE)


def auto_audit_set_enabled(enabled):
    state = auto_audit_load_state()
    state["enabled"] = bool(enabled)
    state["updated_at"] = time.time()
    auto_audit_save_state(state, sync=True)
    return state


def auto_audit_paper_stats():
    try:
        data = paper_store()
    except Exception:
        data = {}
    open_trades = data.get("open", {}) if isinstance(data, dict) and isinstance(data.get("open", {}), dict) else {}
    closed = data.get("closed", []) if isinstance(data, dict) and isinstance(data.get("closed", []), list) else []
    outcomes = [paper_outcome(t) for t in closed if isinstance(t, dict)]
    now_ts = time.time()
    overdue = 0
    near_close = 0
    for t in open_trades.values():
        if not isinstance(t, dict):
            continue
        age = max(0, now_ts - _paper_safe_float(t.get("entry_time"), now_ts))
        if age >= 48 * 3600:
            overdue += 1
        elif age >= 47 * 3600:
            near_close += 1
    return {
        "open": len(open_trades),
        "closed": len(closed),
        "saved": sum(1 for o in outcomes if o in ("avoid_saved", "watch_saved_loss")),
        "missed": sum(1 for o in outcomes if o in ("avoid_missed", "watch_missed_gain")),
        "neutral": sum(1 for o in outcomes if o in ("paper_neutral", "avoid_neutral", "watch_neutral")),
        "pump": sum(1 for o in outcomes if o == "pump_continued_no_pullback"),
        "win": sum(1 for o in outcomes if o == "paper_win"),
        "loss": sum(1 for o in outcomes if o == "paper_loss"),
        "overdue": overdue,
        "near_close": near_close,
        "last_closed_assets": [str(t.get("asset", "?")).upper() for t in closed[-5:] if isinstance(t, dict)],
    }


def auto_audit_learning_stats():
    data = load_json(RESULTS_FILE)
    if not isinstance(data, dict):
        data = {}
    open_items = data.get("open", {}) if isinstance(data.get("open", {}), dict) else {}
    closed = data.get("closed", []) if isinstance(data.get("closed", []), list) else []
    timing_rows = []
    try:
        for rec in list(open_items.values()) + list(closed):
            r = v188_shadow_timing_for_rec(rec)
            if r:
                timing_rows.append(r)
    except Exception:
        timing_rows = []
    return {
        "open": len(open_items),
        "closed": len(closed),
        "timing_checked": len(timing_rows),
        "timing_skip_best": sum(1 for r in timing_rows if r.get("class") == "skip_best"),
        "timing_wait_better": sum(1 for r in timing_rows if r.get("class") in ["delay_better", "delay_slightly_better"]),
        "timing_now_better": sum(1 for r in timing_rows if r.get("class") == "entry_now_better"),
    }


def auto_audit_btc_bucket(value):
    try:
        v = float(value or 0)
    except Exception:
        v = 0.0
    if v <= -4:
        return "btc_drop_4"
    if v <= -2:
        return "btc_drop_2"
    if v < 0:
        return "btc_red"
    if v < 1:
        return "btc_flat_green"
    return "btc_green"



def auto_audit_market_label(ctx):
    """v19.5.2: единая пользовательская метка рынка для Auto-Audit.
    Не меняет внутренний risk engine, только текст и сравнение в self-check.
    """
    if not isinstance(ctx, dict):
        return "unknown"
    if v195_extreme_fear_user_no_buy(ctx) or v115_extreme_fear_btc_weak(ctx):
        return "extreme-fear/no-buy"
    risk = market_risk_level(ctx)
    if risk == "danger":
        return "danger/no-buy"
    if v106_safe_caution(ctx):
        return "safe-caution/no-buy"
    return risk


def auto_audit_new_closed_cards(prev_closed, current_closed, max_cards=3):
    """v19.0: короткие карточки новых closed Paper прямо в Auto-Audit."""
    cards=[]
    try:
        prev=int(prev_closed or 0); cur=int(current_closed or 0)
    except Exception:
        return cards
    if cur <= prev:
        return cards
    try:
        data=paper_store(); closed=data.get("closed", []) if isinstance(data.get("closed", []), list) else []
    except Exception:
        closed=[]
    for t in closed[prev:cur][-max_cards:]:
        if not isinstance(t, dict):
            continue
        asset=str(t.get("asset","?")).upper()
        vtype=str(t.get("virtual_type","?")).replace("_"," ")
        out=paper_outcome(t); label=paper_outcome_label(out)
        r48=(t.get("results",{}) or {}).get("48h")
        pct=f"48ч: {r48:+.2f}%" if isinstance(r48,(int,float)) else "48ч: нет данных"
        if out=="pump_continued_no_pullback": conclusion="не BUY-ошибка; идёт в timing/avoid-pump профиль"
        elif out in ["avoid_saved", "watch_saved_loss"]: conclusion="осторожность/пропуск защитили от плохого входа"
        elif out in ["avoid_neutral", "watch_neutral", "paper_neutral"]: conclusion="нейтрально; веса не усиливать"
        elif out=="paper_win": conclusion="BUY-тест успешен, но нужен ряд закрытий"
        elif out=="paper_loss": conclusion="BUY-тест плохой; похожие входы ослаблять"
        else: conclusion="использовать как наблюдение"
        cards.append(f"• {asset} — {vtype}\n  {pct} | {label}\n  Вывод: {conclusion}")
    return cards


def auto_audit_build_text(reason_lines, ctx, paper, learning, force=False):
    btc_change = v181_safe_float(ctx.get("btc_change", 0), 0) if isinstance(ctx, dict) else 0
    fg_value = ctx.get("fg_value", "?") if isinstance(ctx, dict) else "?"
    macro = ctx.get("macro_mod", 0) if isinstance(ctx, dict) else 0
    # v19.5.2: Auto-Audit показывает тот же no-buy regime, что /market и /signal.
    risk = auto_audit_market_label(ctx) if isinstance(ctx, dict) else "neutral"
    forced = "\nРежим: плановая сводка без спама." if force else ""
    reasons = "\n".join([f"• {r}" for r in reason_lines[:6]]) if reason_lines else "• изменений для срочного действия нет"
    last_assets = ", ".join(paper.get("last_closed_assets") or []) or "нет"
    cards = paper.get("new_closed_cards") or []
    cards_text = ""
    if cards:
        cards_text = "\n\n🧪 Новые закрытые Paper:\n" + "\n".join(cards[:3])
    mode = str(paper.get("auto_audit_mode", "critical-only") or "critical-only")
    return (
        f"🧠 Auto-Audit ALEX EDGE\n"
        f"Версия: {BOT_VERSION}{forced}\nРежим Auto-Audit: {auto_audit_mode_label(mode)}\n\n"
        f"Рынок: {risk} | BTC {btc_change:+.2f}% | страх {fg_value} | новости {int(macro):+d}\n"
        f"Paper: open {paper.get('open',0)} / closed {paper.get('closed',0)} | 🛡 {paper.get('saved',0)} | 🟡 {paper.get('neutral',0)} | 📈 {paper.get('pump',0)}\n"
        f"Learning: open {learning.get('open',0)} / closed48 {learning.get('closed',0)}\n"
        f"Timing: сценариев {learning.get('timing_checked',0)} | полный пропуск лучше {learning.get('timing_skip_best',0)} | ждать лучше {learning.get('timing_wait_better',0)} | сразу лучше {learning.get('timing_now_better',0)}\n\n"
        f"Что изменилось:\n{reasons}{cards_text}\n\n"
        f"Последние closed Paper: {last_assets}\n"
        "Команды для ручной проверки: /learning_sprint /paper /audit_file\n"
        "Автоторговля выключена. Это self-check, не рекомендация покупки."
    )


