        f"Последняя отправка: {str(last_sent) + ' мин назад' if last_sent is not None else 'ещё не было'}\n\n"
        f"Paper сейчас: open {paper.get('open',0)} / closed {paper.get('closed',0)} | 🛡 {paper.get('saved',0)}\n"
