V19119_PAPER_BUY_TYPE = 'PAPER_BUY_DECISION_TEST'
V19119_PAPER_BUY_MAX_ACTIVE = 4
V19119_PAPER_BUY_MIN_SCORE = 52


def v19119_safe_float(x, default=0.0):
    try:
        if x is None:
            return default
        return float(x)
    except Exception:
        return default


def v19119_safe_int(x, default=0):
    try:
        return int(float(x))
    except Exception:
        return default


def v19119_trade_asset(t):
    return str((t or {}).get('asset') or (t or {}).get('symbol') or '?').replace('-USDT','').upper()


def v19119_trade_age_h(t):
    try:
        et = v19119_safe_float((t or {}).get('entry_time'), 0)
        if et <= 0:
            return 0.0
        return max(0.0, (time.time() - et) / 3600.0)
    except Exception:
        return 0.0


def v19119_entry_price(t):
    for k in ['last_price', 'current_price_v19117', 'current_price', 'entry_price', 'price']:
        v = v19119_safe_float((t or {}).get(k), 0)
        if v > 0:
            return v
    return 0.0


def v19119_pnl_pct(t):
    if not isinstance(t, dict):
        return 0.0
    for k in ['last_pct', 'current_pnl_v19117', 'pnl_pct', 'pct']:
        v = t.get(k)
        if isinstance(v, (int, float)):
            return float(v)
    ep = v19119_safe_float(t.get('entry_price'), 0)
    cp = v19119_entry_price(t)
    if ep > 0 and cp > 0:
        return round((cp - ep) / ep * 100.0, 2)
    return 0.0


def v19119_is_quality_probe(t):
    if not isinstance(t, dict):
        return False
    vt = str(t.get('virtual_type','')).upper()
    return bool(t.get('is_probe')) or vt == 'VIRTUAL_PROBE_ENTRY_TEST'


def v19119_is_paper_buy_decision(t):
    if not isinstance(t, dict):
        return False
    return str(t.get('virtual_type','')).upper() == V19119_PAPER_BUY_TYPE


def v19119_open_trades():
    try:
        data = paper_store()
        op = data.get('open', {}) if isinstance(data.get('open', {}), dict) else {}
        return data, op
    except Exception:
        return {'open': {}, 'closed': []}, {}


def v19119_active_paper_buy_assets(open_trades=None):
    if open_trades is None:
        _, open_trades = v19119_open_trades()
    assets = set()
    for t in (open_trades or {}).values():
        if v19119_is_paper_buy_decision(t):
            a = v19119_trade_asset(t)
            if a:
                assets.add(a)
    return assets


def v19119_quality_probe_candidates_from_store():
    data, open_trades = v19119_open_trades()
    rows = []
    for key, t in list((open_trades or {}).items()):
        try:
            if not v19119_is_quality_probe(t):
                continue
            asset = v19119_trade_asset(t)
            if not asset or asset in globals().get('STABLE_SKIP_ASSETS', set()):
                continue
            price = v19119_entry_price(t)
            if price <= 0:
                continue
            row = dict(t)
            row['_paper_key'] = key
            row['_paper_asset'] = asset
            row['_paper_price'] = price
            row['_paper_pct'] = v19119_pnl_pct(t)
            row['_paper_age_h'] = v19119_trade_age_h(t)
            rows.append(row)
        except Exception:
            continue
    return rows


def v19119_decision_from_probe(t):
    asset = v19119_trade_asset(t)
    price = v19119_entry_price(t)
    pnl = v19119_pnl_pct(t)
    entry_score = v19119_safe_int(t.get('score', t.get('entry_score', 55)), 55)
    btc = v19119_safe_float(t.get('btc_change'), 0)
    macro = v19119_safe_float(t.get('macro_mod'), 0)
    change24 = v19119_safe_float(t.get('change_24'), 0)
    age_h = v19119_trade_age_h(t)
    is_quality = bool(t.get('is_quality')) or asset in globals().get('QUALITY_LEARNING_ASSETS', set())

    score = 45
    reasons = []
    risks = []

    # Качество актива и исходный probe-score.
    if is_quality:
        score += 8
        reasons.append('quality-актив из белого списка')
    if entry_score >= 68:
        score += 12; reasons.append('сильный исходный probe-score')
    elif entry_score >= 55:
        score += 7; reasons.append('нормальный исходный probe-score')
    elif entry_score >= 35:
        score -= 4; risks.append('исходный probe-score слабый')
    else:
        score -= 10; risks.append('исходный probe-score очень слабый')

    # Не догоняем сильную свечу, но тренируем micro-buy на восстановлении/нейтрали.
    if -1.7 <= pnl <= 1.8:
        score += 9
        reasons.append('точка не выглядит погоней за свечой')
    elif -3.2 <= pnl < -1.7:
        score -= 3
        risks.append('есть ранняя просадка, нужен малый paper-размер')
    elif pnl < -3.2:
        score -= 14
        risks.append('глубокая ранняя просадка')
    elif 1.8 < pnl <= 4.0:
        score += 2
        reasons.append('есть импульс, но без сильной погони')
    else:
        score -= 7
        risks.append('риск догонять перегретое движение')

    # Фон рынка.
    if btc >= 0.2:
        score += 5; reasons.append('BTC не давит')
    elif btc <= -1.5:
        score -= 8; risks.append('BTC давит на альты')
    if macro <= -8:
        score -= 10; risks.append('фон рынка против альтов')
    elif macro >= -2:
        score += 2

    # Momentum 24h: умеренный рост лучше, чем экстремальный памп.
    if -2 <= change24 <= 6:
        score += 3
    elif change24 > 10:
        score -= 7; risks.append('24ч движение похоже на погоню за пампом')

    # Первые 12-24ч probe уже дают больше информации, чем мгновенный вход.
    if age_h >= 12:
        score += 3; reasons.append('probe уже прошла раннюю фазу')

    score = max(0, min(100, int(round(score))))
    if score >= 66:
        decision = '🟢 PAPER BUY'
        size = '2.0% paper-capital'
        tier = 'quality_buy_test'
    elif score >= V19119_PAPER_BUY_MIN_SCORE:
        decision = '🟡 PAPER MICRO-BUY'
        size = '1.0% paper-capital'
        tier = 'micro_buy_test'
    elif score >= 45:
        decision = '🟠 PAPER WATCH, BUY НЕ ОТКРЫВАТЬ'
        size = '0%'
        tier = 'watch_only'
    else:
        decision = '🔴 PAPER BUY ЗАПРЕЩЁН'
        size = '0%'
        tier = 'reject'

    try:
        stop_pct = -3.0 if score >= 66 else -2.2
        target1_pct = 2.5 if score >= 66 else 1.8
        target2_pct = 5.0 if score >= 66 else 3.5
        stop = price * (1 + stop_pct/100.0)
        target1 = price * (1 + target1_pct/100.0)
        target2 = price * (1 + target2_pct/100.0)
    except Exception:
        stop = target1 = target2 = 0
        stop_pct = target1_pct = target2_pct = 0

    return {
        'asset': asset,
        'price': price,
        'pnl': round(float(pnl or 0), 2),
        'age_h': round(float(age_h or 0), 1),
        'entry_score': entry_score,
        'decision_score': score,
        'decision': decision,
        'tier': tier,
        'paper_size': size,
        'reasons': reasons[:4] or ['paper BUY training candidate'],
        'risks': risks[:4] or ['без критичных блокеров'],
        'stop': round(stop, 10),
        'target1': round(target1, 10),
        'target2': round(target2, 10),
        'stop_pct': stop_pct,
        'target1_pct': target1_pct,
        'target2_pct': target2_pct,
        'btc_change': btc,
        'macro_mod': macro,
        'change_24': change24,
        'source_probe_key': t.get('_paper_key') or t.get('id',''),
        'probe_reason': t.get('probe_reason') or t.get('verdict') or 'quality probe',
    }


def v19119_ranked_paper_buy_decisions():
    probes = v19119_quality_probe_candidates_from_store()
    out = []
    for t in probes:
        try:
            d = v19119_decision_from_probe(t)
            out.append(d)
        except Exception:
            continue
    out.sort(key=lambda x: (x.get('decision_score',0), x.get('pnl',0)), reverse=True)
    return out


def v19119_open_paper_buy_decisions(create=True, max_new=2, force_one=False):
    data, open_trades = v19119_open_trades()
    if not isinstance(open_trades, dict):
        open_trades = {}
    active_assets = v19119_active_paper_buy_assets(open_trades)
    active_count = len(active_assets)
    decisions = v19119_ranked_paper_buy_decisions()
    created = []
    skipped = []

    if not create:
        return {'created': created, 'skipped': decisions, 'active': active_count, 'decisions': decisions}

    now = time.time()
    slots = max(0, int(V19119_PAPER_BUY_MAX_ACTIVE) - active_count)
    limit = min(int(max_new or 0), slots)
    if limit <= 0:
        return {'created': created, 'skipped': decisions, 'active': active_count, 'decisions': decisions}

    eligible = [d for d in decisions if d.get('tier') in ['quality_buy_test','micro_buy_test'] and d.get('asset') not in active_assets]
    if not eligible and force_one:
        fallback = [d for d in decisions if d.get('decision_score',0) >= 45 and d.get('asset') not in active_assets]
        eligible = fallback[:1]

    for d in eligible[:limit]:
        try:
            asset = d.get('asset')
            price = v19119_safe_float(d.get('price'), 0)
            if not asset or price <= 0 or asset in active_assets:
                continue
            key = paper_trade_key(asset, V19119_PAPER_BUY_TYPE, now)
            if key in open_trades:
                continue
            open_trades[key] = {
                'id': key,
                'asset': asset,
                'entry_time': now,
                'entry_price': round(price, 10),
                'last_price': round(price, 10),
                'last_pct': 0.0,
                'score': int(d.get('decision_score', 0) or 0),
                'entry_score': int(d.get('entry_score', 0) or 0),
                'master_score': int(d.get('decision_score', 0) or 0),
                'source_action': 'PAPER_BUY_DECISION',
                'virtual_type': V19119_PAPER_BUY_TYPE,
                'verdict': d.get('decision'),
                'is_quality': True,
                'is_paper_buy_decision': True,
                'paper_buy_tier': d.get('tier'),
                'paper_size': d.get('paper_size'),
                'entry_plan': {
                    'target1': d.get('target1'),
                    'target2': d.get('target2'),
                    'stop': d.get('stop'),
                    'target1_pct': d.get('target1_pct'),
                    'target2_pct': d.get('target2_pct'),
                    'stop_pct': d.get('stop_pct'),
                    'cancel_rule': 'если BTC резко давит или цена уходит ниже stop — paper BUY считается плохим/ранним',
                },
                'decision_reasons': d.get('reasons', []),
                'decision_risks': d.get('risks', []),
                'source_probe_key': d.get('source_probe_key'),
                'probe_pnl_at_decision': d.get('pnl'),
                'probe_age_h_at_decision': d.get('age_h'),
                'btc_change': round(float(d.get('btc_change',0) or 0), 3),
                'macro_mod': d.get('macro_mod'),
                'change_24': round(float(d.get('change_24',0) or 0), 3),
                'results': {},
                'result_details': {},
                'status': 'open',
                'note': 'PAPER BUY only: реальные деньги не используются, автоторговля OFF, BUY-веса +0',
                'created_by': 'v19.11.9.1 GITHUB REF UPDATE FIX',
            }
            created.append(d)
            active_assets.add(asset)
        except Exception as e:
            skipped.append({'asset': d.get('asset','?'), 'decision': 'error', 'decision_score': 0, 'risks': [str(e)[:120]]})
            continue

    if created:
        data['open'] = open_trades
        data['last_paper_buy_decision_at'] = now
        data['last_paper_buy_decision_version'] = BOT_VERSION
        save_paper_store(data, sync=False)
    return {'created': created, 'skipped': decisions, 'active': len(active_assets), 'decisions': decisions}


def v19119_format_price(x):
    try:
        if 'compact_price' in globals():
            return compact_price(x)
    except Exception:
        pass
    try:
        return f'${float(x):.6g}'
    except Exception:
        return str(x)


def v19119_active_paper_buy_rows(limit=8):
    _, open_trades = v19119_open_trades()
    rows = []
    for t in list((open_trades or {}).values()):
        if not v19119_is_paper_buy_decision(t):
            continue
        asset = v19119_trade_asset(t)
        entry = v19119_safe_float(t.get('entry_price'), 0)
        last = v19119_safe_float(t.get('last_price'), entry)
        pct = t.get('last_pct')
        if not isinstance(pct, (int, float)):
            pct = ((last-entry)/entry*100.0) if entry and last else 0
        age_h = v19119_trade_age_h(t)
        plan = t.get('entry_plan', {}) if isinstance(t.get('entry_plan', {}), dict) else {}
        rows.append(
            f"• {asset}: {t.get('verdict','PAPER BUY')} | {v19119_format_price(entry)} → {v19119_format_price(last)} ({float(pct or 0):+.2f}%) | {age_h:.1f}ч | stop {v19119_format_price(plan.get('stop',0))} | T1 {v19119_format_price(plan.get('target1',0))}"
        )
        if len(rows) >= int(limit or 8):
            break
    return rows


def v19119_paper_buy_decision_report(create=False):
    try:
        res = v19119_open_paper_buy_decisions(create=bool(create), max_new=2, force_one=False)
    except Exception as e:
        return (
            '🟢 Paper BUY Decision Layer\n\n'
            f'Версия: {BOT_VERSION}\n'
            f'⚠️ Не смог построить paper BUY слой: {str(e)[:180]}\n\n'
            'Реальные покупки 0, автоторговля OFF.'
        )

    created = res.get('created', []) or []
    decisions = res.get('decisions', []) or []
    active_rows = v19119_active_paper_buy_rows(limit=6)
    lines = [
        '🟢 Paper BUY Decision Layer',
        f'Версия: {BOT_VERSION}',
        '',
        'Режим: только paper BUY. Реальные покупки 0, автоторговля OFF, BUY-веса +0.',
        'Задача: бот тренируется принимать BUY-решение с входом/стопом/целями, а не только наблюдать.',
        '',
        f'Создано новых paper BUY: {len(created)}',
        f'Активных paper BUY: {len(active_rows)}',
    ]
    if created:
        lines += ['', 'Новые paper BUY:']
        for d in created:
            lines.append(
                f"• {d.get('asset')}: {d.get('decision')} | score {d.get('decision_score')}/100 | вход {v19119_format_price(d.get('price'))} | размер {d.get('paper_size')}"
            )
            lines.append(
                f"  План: T1 {v19119_format_price(d.get('target1'))} / T2 {v19119_format_price(d.get('target2'))} / stop {v19119_format_price(d.get('stop'))}"
            )
            lines.append('  Причина: ' + '; '.join(d.get('reasons', [])[:3]))
    elif create:
        lines += ['', 'Новые paper BUY не созданы: уже есть активные BUY по подходящим монетам или кандидаты ниже порога.']

    if active_rows:
        lines += ['', 'Открытые paper BUY:'] + active_rows
    else:
        lines += ['', 'Открытых paper BUY пока нет. Сначала нужны активные quality-probe: /quality_probe.']

    if decisions:
        lines += ['', 'Кандидаты/отсев сейчас:']
        for d in decisions[:6]:
            lines.append(
                f"• {d.get('asset')}: {d.get('decision')} | score {d.get('decision_score')}/100 | probe {d.get('pnl'):+.2f}% | риск: {'; '.join(d.get('risks', [])[:2])}"
            )
    else:
        lines += ['', 'Кандидатов нет: нет активных quality-probe в paper-store.']

    lines += [
        '',
        'Проверка результата: 6ч/24ч/48ч через обычный paper finalizer.',
        'Команды: /paper_buy | /paper_buy_status | /paper | /lesson_engine | /audit_file',
    ]
    return '\n'.join(lines)


