# === v19.11.9.1 GITHUB REF UPDATE FIX ===
# Причина: atomic backup commit создавался, но обновление branch ref падало 404,
# потому что GitHub Update reference использует /git/refs/... (plural),
# а не /git/ref/... (singular). Это сервисный hotfix деплойщика.
# Торговая логика, paper BUY layer, BUY-веса, Risk Engine и автоторговля не меняются.

BOT_VERSION = "v20.9.2 MOBILE SAFE FILE FIX"


def _v191191_branch_ref_name():
    try:
        br = str(GITHUB_BRANCH or "main").strip()
        br = br.replace("refs/heads/", "").replace("heads/", "").strip("/")
        return br or "main"
    except Exception:
        return "main"


def github_put_files_atomic(file_map, message):
    """
    v19.11.9.1:
    Atomic GitHub commit for backup + main.py.
    Fixes GitHub ref update endpoint:
      GET reference:    /git/ref/heads/<branch>
      PATCH reference:  /git/refs/heads/<branch>
    """
    if not github_ready():
        raise Exception("GitHub ENV не заполнены: GITHUB_TOKEN, GITHUB_REPO, GITHUB_BRANCH, GITHUB_PATH")
    if not isinstance(file_map, dict) or not file_map:
        raise Exception("Нет файлов для atomic GitHub commit")

    branch = _v191191_branch_ref_name()
    get_ref_url = github_api_url(f"git/ref/heads/{branch}")
    patch_ref_url = github_api_url(f"git/refs/heads/{branch}")

    r = requests.get(get_ref_url, headers=github_headers(), timeout=30)
    if r.status_code >= 300:
        # Some GitHub installations also accept plural for GET; keep fallback defensive.
        r2 = requests.get(patch_ref_url, headers=github_headers(), timeout=30)
        if r2.status_code < 300:
            r = r2
        else:
            raise Exception(f"GitHub ref GET error {r.status_code}: {r.text[:600]}")

    base_commit_sha = ((r.json().get("object") or {}).get("sha") or "").strip()
    if not base_commit_sha:
        raise Exception("GitHub ref не вернул sha последнего commit")

    r = requests.get(github_api_url(f"git/commits/{base_commit_sha}"), headers=github_headers(), timeout=30)
    if r.status_code >= 300:
        raise Exception(f"GitHub commit GET error {r.status_code}: {r.text[:600]}")
    base_tree_sha = ((r.json().get("tree") or {}).get("sha") or "").strip()
    if not base_tree_sha:
        raise Exception("GitHub commit не вернул tree sha")

    tree_items = []
    for path, content_bytes in file_map.items():
        repo_path = str(path or "").strip().lstrip("/")
        if not repo_path:
            continue
        if not isinstance(content_bytes, (bytes, bytearray)):
            content_bytes = bytes(content_bytes)
        blob_sha = github_create_blob(content_bytes)
        tree_items.append({
            "path": repo_path,
            "mode": "100644",
            "type": "blob",
            "sha": blob_sha,
        })

    if not tree_items:
        raise Exception("Atomic commit: нет валидных путей файлов")

    r = requests.post(
        github_api_url("git/trees"),
        headers=github_headers(),
        json={"base_tree": base_tree_sha, "tree": tree_items},
        timeout=40,
    )
    if r.status_code >= 300:
        raise Exception(f"GitHub tree error {r.status_code}: {r.text[:600]}")
    new_tree_sha = r.json().get("sha")

    r = requests.post(
        github_api_url("git/commits"),
        headers=github_headers(),
        json={"message": message, "tree": new_tree_sha, "parents": [base_commit_sha]},
        timeout=40,
    )
    if r.status_code >= 300:
        raise Exception(f"GitHub commit create error {r.status_code}: {r.text[:600]}")
    new_commit = r.json()
    new_commit_sha = (new_commit.get("sha") or "").strip()
    if not new_commit_sha:
        raise Exception("GitHub commit create не вернул sha")

    r = requests.patch(
        patch_ref_url,
        headers=github_headers(),
        json={"sha": new_commit_sha, "force": False},
        timeout=40,
    )
    if r.status_code >= 300:
        # One retry with fresh ref if branch moved while we were building the commit.
        if r.status_code in (409, 422):
            time.sleep(1)
            fresh = requests.get(get_ref_url, headers=github_headers(), timeout=30)
            fresh_sha = (((fresh.json() if fresh.status_code < 300 else {}) .get("object") or {}).get("sha") or "").strip()
            if fresh_sha and fresh_sha != base_commit_sha:
                raise Exception(
                    "GitHub ref update conflict: branch moved during atomic commit. "
                    "Повтори загрузку файла ещё раз."
                )
        raise Exception(f"GitHub ref update error {r.status_code}: {r.text[:600]}")

    return {
        "commit": new_commit,
        "sha": new_commit_sha,
        "files": list(file_map.keys()),
        "ref_endpoint": f"git/refs/heads/{branch}",
    }


