    try:
        return (datetime.utcnow() + timedelta(hours=MOSCOW_OFFSET_HOURS)).strftime('%Y-%m-%d %H:%M:%S')
    except Exception:
        return datetime.utcnow().strftime('%Y-%m-%d %H:%M:%S')


