def _v1911103_load_log():
    try:
        data = load_json(AUTO_AUDIT_SILENT_LOG_FILE)
        if not isinstance(data, dict):
            data = {}
    except Exception:
        data = {}
    items = data.get('items', []) if isinstance(data.get('items', []), list) else []
