def v191111_lessons():
    try:
        rows = v19118_load_lessons()
        return rows if isinstance(rows, list) else []
    except Exception:
        return []


def v191111_lesson_class(row):
    text = str(
        (row or {}).get('classification')
        or (row or {}).get('label')
        or (row or {}).get('status')
        or ''
    ).lower()
    if any(x in text for x in ['good', 'useful', 'полез', 'хорош']):
        return 'good'
    if any(x in text for x in ['bad', 'early', 'drawdown', 'плох', 'ранн', 'просад']):
        return 'bad'
    return 'neutral'


def v191111_lesson_stats(asset=None):
    asset = str(asset or '').upper().strip()
    dedup = {}
    for row in v191111_lessons():
        if not isinstance(row, dict):
            continue
        row_asset = str(row.get('asset') or '').upper().strip()
        if asset and row_asset != asset:
            continue
        try:
            entry_id = int(float(row.get('entry_time', 0) or 0))
        except Exception:
            entry_id = 0
        trial_key = f"{row_asset}:{entry_id}" if entry_id else str(row.get('key') or f"{row_asset}:{len(dedup)}")
        stage = str(row.get('stage') or '').lower()
        stage_rank = 2 if '48' in stage or 'historical' in stage else (1 if '24' in stage else 0)
        previous = dedup.get(trial_key)
        if previous is None or stage_rank >= previous[0]:
            dedup[trial_key] = (stage_rank, row)
    rows = [item[1] for item in dedup.values()]
    stats = {
        'asset': asset,
        'total': len(rows),
        'good': 0,
        'neutral': 0,
        'bad': 0,
        'avg_pct': 0.0,
        'paper_delta': 0,
    }
    pnl_values = []
    for row in rows:
        stats[v191111_lesson_class(row)] += 1
        try:
            stats['paper_delta'] += int(row.get('paper_delta') or row.get('paperΔ') or 0)
        except Exception:
            pass
        try:
            value = row.get('pct') if row.get('pct') is not None else row.get('pnl_pct')
            if value is not None:
                pnl_values.append(float(value))
        except Exception:
            pass
    if pnl_values:
        stats['avg_pct'] = round(sum(pnl_values) / len(pnl_values), 2)
    return stats


def v191113_historical_buy_backfill():
    """Backfill only closed BUY trials; WATCH/AVOID outcomes never become entry lessons."""
    result = {'closed': 0, 'eligible': 0, 'added': 0, 'already': 0, 'skipped': 0, 'error': ''}
    try:
        data = paper_store()
        closed = data.get('closed', []) if isinstance(data.get('closed', []), list) else []
        lessons = v19118_load_lessons(data)
        if not isinstance(lessons, list):
            lessons = []
        result['closed'] = len(closed)
        existing = {str(row.get('key') or '') for row in lessons if isinstance(row, dict)}
        existing_final_trials = set()
        for row in lessons:
            if not isinstance(row, dict):
                continue
            stage_name = str(row.get('stage') or '').lower()
            if '48' not in stage_name and 'historical' not in stage_name:
                continue
            try:
                trial_entry = int(float(row.get('entry_time', 0) or 0))
            except Exception:
                trial_entry = 0
            trial_asset = str(row.get('asset') or '').upper().strip()
            if trial_asset and trial_entry:
                existing_final_trials.add((trial_asset, trial_entry))
        additions = []
        for trade in closed:
            if not isinstance(trade, dict):
                result['skipped'] += 1
                continue
            virtual_type = str(trade.get('virtual_type') or '').upper()
            source_action = str(trade.get('source_action') or trade.get('action') or '').upper()
            is_buy = (
                'BUY' in virtual_type
                or 'BUY' in source_action
                or bool(trade.get('is_paper_buy_decision'))
            )
            excluded = any(token in virtual_type for token in ['WATCH', 'OBSERVE', 'MONITOR', 'AVOID'])
            if not is_buy or excluded:
                continue
            asset = v19118_trade_asset(trade)
            entry_time = v19118_entry_time(trade)
            if not asset or entry_time <= 0:
                result['skipped'] += 1
                continue
            results = trade.get('results', {}) if isinstance(trade.get('results'), dict) else {}
            pct = results.get('48h')
            stage = '48h_historical_buy'
            if not isinstance(pct, (int, float)):
                pct = results.get('24h')
                stage = '24h_historical_buy'
            if not isinstance(pct, (int, float)):
                result['skipped'] += 1
                continue
            result['eligible'] += 1
            key = f"{asset}:{int(float(entry_time))}:{stage}"
            trial_identity = (asset, int(float(entry_time)))
            if key in existing or (stage.startswith('48') and trial_identity in existing_final_trials):
                result['already'] += 1
                continue
            classification = v19118_lesson_classification(float(pct), stage=stage)
            snapshot = trade.get('probe_entry_snapshot_v19117', {})
            if not isinstance(snapshot, dict):
                snapshot = {}
            additions.append({
                'key': key,
                'asset': asset,
                'stage': stage,
                'version': V191111_VERSION,
                'entry_time': float(entry_time),
                'lesson_time': time.time(),
                'entry_price': v19118_entry_price(trade),
                'pct': round(float(pct), 2),
                'bucket': classification.get('bucket'),
                'label': classification.get('label'),
                'lesson': classification.get('lesson'),
                'paper_delta': classification.get('paper_delta'),
                'lesson_score': classification.get('score'),
                'entry_score': v19118_safe_int(trade.get('score', trade.get('entry_score', 0)), 0),
                'results': {k: v for k, v in results.items() if k in ['1h', '3h', '6h', '12h', '24h', '48h']},
                'snapshot': {
                    'btc_change': snapshot.get('btc_change', trade.get('btc_change')),
                    'fear': snapshot.get('fear'),
                    'news': snapshot.get('news'),
                    'rsi': snapshot.get('rsi'),
                    'volume_trend': snapshot.get('volume_trend'),
                    'risk_level': snapshot.get('risk_level'),
                    'change_24': snapshot.get('change_24', trade.get('change_24')),
                },
                'source': 'historical_closed_buy_backfill',
            })
            existing.add(key)
            if stage.startswith('48'):
                existing_final_trials.add(trial_identity)
        if additions:
            lessons.extend(additions)
            data['probe_lessons_v19118'] = lessons[-500:]
            data['last_historical_buy_backfill_at'] = time.time()
            data['last_historical_buy_backfill_version'] = V191111_VERSION
            save_paper_store(data, sync=False)
        result['added'] = len(additions)
    except Exception as exc:
        result['error'] = str(exc)[:180]
    return result


def v191113_policy_calibration_lines(backfill=None):
    try:
        metrics = _v1982_metrics()
    except Exception:
        metrics = {}
    closed = int(metrics.get('closed', 0) or 0)
    protection = int(metrics.get('protection', 0) or 0)
    missed = int(metrics.get('missed', 0) or 0)
    buy_win = int(metrics.get('buy_win', 0) or 0)
    buy_loss = int(metrics.get('buy_loss', 0) or 0)
    entry_error = int(metrics.get('entry_error', 0) or 0)
    correct = protection + buy_win
    errors = missed + entry_error
    decisive = correct + errors
    precision = correct / float(decisive) * 100.0 if decisive else 0.0
    coverage = decisive / float(closed) * 100.0 if closed else 0.0
    backfill = backfill if isinstance(backfill, dict) else {}
    return [
        '🧮 HISTORICAL POLICY VS ENTRY CALIBRATION',
        f'• закрытых PAPER: {closed} | значимых решений: {decisive} ({coverage:.1f}% coverage)',
        f'• защита/решение было верным: {correct} | пропуски/ошибки: {errors} | precision {precision:.1f}%',
        f'• BUY-тесты: wins {buy_win} | losses {buy_loss} | entry errors {entry_error}',
        f"• historical BUY backfill: eligible {backfill.get('eligible', 0)} | added {backfill.get('added', 0)} | already {backfill.get('already', 0)}",
        '• защитная precision не считается готовностью к автопокупкам; для неё нужны успешные BUY-входы.',
    ]


