def v191120_fetch_4h_candles(asset, pages=2, bars_per_page=1200):
    """Fetch roughly 13 months of 4h candles instead of KuCoin's short default page."""
    rows_by_ts = {}
    end_at = int(time.time())
    page_seconds = int(bars_per_page) * 4 * 3600
    for _ in range(max(1, int(pages or 1))):
        start_at = max(0, end_at - page_seconds)
        try:
            response = requests.get(
                "https://api.kucoin.com/api/v1/market/candles",
                params={
                    "symbol": f"{asset}-USDT",
                    "type": "4hour",
                    "startAt": start_at,
                    "endAt": end_at,
                },
                timeout=12,
            ).json()
            if response.get("code") != "200000":
                break
            raw_rows = response.get("data", [])
            if not isinstance(raw_rows, list) or not raw_rows:
                break
            oldest = None
            for candle in raw_rows:
                try:
                    ts = int(candle[0])
                    rows_by_ts[ts] = {
                        'ts': ts,
                        'open': float(candle[1]),
                        'close': float(candle[2]),
                        'high': float(candle[3]),
                        'low': float(candle[4]),
                        'volume': float(candle[5]),
                    }
                    oldest = ts if oldest is None else min(oldest, ts)
                except Exception:
                    continue
            if oldest is None or oldest >= end_at:
                break
            end_at = oldest - 1
        except Exception as exc:
            print(f"walk-forward candles error {asset}: {exc}")
            break
    return [rows_by_ts[ts] for ts in sorted(rows_by_ts)][-2400:]


def v191120_ema(values, period):
    values = [float(value) for value in values]
    if not values:
        return 0.0
    alpha = 2.0 / (float(period) + 1.0)
    result = values[0]
    for value in values[1:]:
        result = alpha * value + (1.0 - alpha) * result
    return result


def v191120_rsi(values, period=14):
    values = [float(value) for value in values]
    if len(values) < period + 1:
        return 50.0
    gains, losses = [], []
    for before, after in zip(values[-period - 1:-1], values[-period:]):
        delta = after - before
        gains.append(max(0.0, delta))
        losses.append(max(0.0, -delta))
    avg_gain = sum(gains) / period
    avg_loss = sum(losses) / period
    if avg_loss <= 0:
        return 100.0 if avg_gain > 0 else 50.0
    rs = avg_gain / avg_loss
    return 100.0 - 100.0 / (1.0 + rs)


def v191120_pct(start, end):
    try:
        start = float(start)
        end = float(end)
        return (end - start) / start * 100.0 if start else 0.0
    except Exception:
        return 0.0


def v2000_market_regime(features):
    btc = float(features.get('btc_24h', 0) or 0)
    ret4 = float(features.get('ret_4h', 0) or 0)
    ret24 = float(features.get('ret_24h', 0) or 0)
    volume = float(features.get('volume_ratio', 1) or 1)
    volatility = float(features.get('range14', 0) or 0)
    btc_above = bool(features.get('btc_above_ema20'))
    asset_above = bool(features.get('above_ema20'))
    if btc <= -2.0 or (volatility >= 22 and ret24 <= -3):
        return 'panic'
    if btc >= 0 and ret4 >= 0 and -5 <= ret24 < 0:
        return 'recovery'
    if btc >= 0.5 and btc_above and asset_above and ret24 >= 1 and volume >= 0.9:
        return 'growth'
    if abs(btc) < 1.0 and -3 <= ret24 <= 3:
        return 'sideways'
    return 'decline'


def v191120_feature_score(candles, index, btc_by_ts):
    current = candles[index]
    closes = [row['close'] for row in candles[:index + 1]]
    volumes = [row['volume'] for row in candles[:index + 1]]
    price = float(current['close'])
    ret_4h = v191120_pct(closes[index - 1], price)
    ret_24h = v191120_pct(closes[index - 6], price)
    ema20 = v191120_ema(closes[-20:], 20)
    rsi14 = v191120_rsi(closes, 14)
    volume_base = sum(volumes[index - 12:index]) / 12.0 if index >= 12 else 0.0
    volume_ratio = volumes[index] / volume_base if volume_base > 0 else 1.0
    high20 = max(row['high'] for row in candles[index - 19:index + 1])
    low14 = min(row['low'] for row in candles[index - 13:index + 1])
    drawdown20 = v191120_pct(high20, price)
    range14 = v191120_pct(low14, max(row['high'] for row in candles[index - 13:index + 1]))
    btc = btc_by_ts.get(int(current['ts']), {})
    btc_24h = float(btc.get('ret_24h', 0) or 0)
    btc_above_ema = bool(btc.get('above_ema20', False))

    score = 50
    reasons = []
    if -3.0 <= ret_24h <= 4.5:
        score += 7; reasons.append('controlled 24h move')
    elif ret_24h > 9:
        score -= 10; reasons.append('overheated 24h move')
    elif ret_24h < -6:
        score -= 7; reasons.append('strong 24h weakness')
    if -1.5 <= ret_4h <= 2.5:
        score += 4
    elif ret_4h > 5:
        score -= 6
    if 42 <= rsi14 <= 62:
        score += 7; reasons.append('balanced RSI')
    elif rsi14 >= 72:
        score -= 9; reasons.append('overbought RSI')
    elif rsi14 <= 30:
        score -= 4
    if 0.9 <= volume_ratio <= 2.2:
        score += 5; reasons.append('confirmed volume')
    elif volume_ratio < 0.65:
        score -= 4
    if price >= ema20:
        score += 5
    else:
        score -= 3
    if -8 <= drawdown20 <= -1:
        score += 4; reasons.append('not chasing local high')
    elif drawdown20 > -0.5:
        score -= 3
    if range14 >= 24:
        score -= 5; reasons.append('high volatility')
    if btc_24h >= 0 and btc_above_ema:
        score += 7; reasons.append('BTC supportive')
    elif btc_24h <= -2:
        score -= 10; reasons.append('BTC pressure')
    elif not btc_above_ema:
        score -= 4
    result = {
        'score': max(0, min(100, int(round(score)))),
        'ret_4h': round(ret_4h, 3),
        'ret_24h': round(ret_24h, 3),
        'rsi14': round(rsi14, 2),
        'volume_ratio': round(volume_ratio, 3),
        'drawdown20': round(drawdown20, 3),
        'range14': round(range14, 3),
        'btc_24h': round(btc_24h, 3),
        'above_ema20': bool(price >= ema20),
        'btc_above_ema20': btc_above_ema,
        'reasons': reasons[:5],
    }
    result['regime'] = v2000_market_regime(result)
    return result


def v191120_btc_features(candles):
    result = {}
    closes = []
    for index, row in enumerate(candles):
        closes.append(float(row['close']))
        if index < 20:
            continue
        result[int(row['ts'])] = {
            'ret_24h': v191120_pct(closes[index - 6], closes[index]) if index >= 6 else 0.0,
            'above_ema20': closes[index] >= v191120_ema(closes[-20:], 20),
        }
    return result


def v191122_simulate_plan(entry, future, target_pct=2.0, stop_pct=-3.0):
    """Conservative 4h-bar simulation: if target and stop touch together, stop wins."""
    entry = float(entry or 0)
    if entry <= 0 or not future:
        return {'return_pct': 0.0, 'outcome': 'no_data', 'bars': 0}
    target = entry * (1.0 + float(target_pct) / 100.0)
    stop = entry * (1.0 + float(stop_pct) / 100.0)
    for bar_index, bar in enumerate(future, start=1):
        low = float(bar.get('low', entry) or entry)
        high = float(bar.get('high', entry) or entry)
        stop_hit = low <= stop
        target_hit = high >= target
        if stop_hit:
            return {'return_pct': float(stop_pct), 'outcome': 'stop', 'bars': bar_index}
        if target_hit:
            return {'return_pct': float(target_pct), 'outcome': 'target', 'bars': bar_index}
    final_return = v191120_pct(entry, future[-1].get('close', entry))
    return {'return_pct': round(final_return, 3), 'outcome': 'timeout', 'bars': len(future)}


def v191120_build_dataset(candles_by_asset):
    btc = candles_by_asset.get('BTC', [])
    btc_by_ts = v191120_btc_features(btc)
    samples = []
    for asset, candles in candles_by_asset.items():
        if asset == 'BTC' or len(candles) < 60:
            continue
        for index in range(30, len(candles) - 12, 3):
            try:
                features = v191120_feature_score(candles, index, btc_by_ts)
                entry = float(candles[index]['close'])
                future = candles[index + 1:index + 13]
                plan = v191122_simulate_plan(entry, future)
                row = {
                    'asset': asset,
                    'ts': int(candles[index]['ts']),
                    **features,
                    '4h': round(v191120_pct(entry, candles[index + 1]['close']), 3),
                    '12h': round(v191120_pct(entry, candles[index + 3]['close']), 3),
                    '24h': round(v191120_pct(entry, candles[index + 6]['close']), 3),
                    '48h': round(v191120_pct(entry, candles[index + 12]['close']), 3),
                    'mae48': round(v191120_pct(entry, min(item['low'] for item in future)), 3),
                    'mfe48': round(v191120_pct(entry, max(item['high'] for item in future)), 3),
                    'plan_return': round(float(plan.get('return_pct', 0) or 0), 3),
                    'plan_outcome': plan.get('outcome'),
                    'plan_bars': int(plan.get('bars', 0) or 0),
                }
                samples.append(row)
            except Exception:
                continue
    return sorted(samples, key=lambda row: (row['ts'], row['asset']))


def v191120_metrics(samples, threshold):
    selected = [row for row in samples if int(row.get('score', 0) or 0) >= int(threshold)]
    if not selected:
        return {
            'threshold': threshold, 'n': 0, 'avg48': 0.0, 'median48': 0.0,
            'win_rate': 0.0, 'bad_rate': 0.0, 'avg_mae': 0.0,
            'plan_expectancy': 0.0, 'plan_win_rate': 0.0, 'plan_stop_rate': 0.0,
        }
    outcomes = sorted(float(row.get('48h', 0) or 0) for row in selected)
    plan_returns = [float(row.get('plan_return', 0) or 0) for row in selected]
    middle = len(outcomes) // 2
    median = outcomes[middle] if len(outcomes) % 2 else (outcomes[middle - 1] + outcomes[middle]) / 2.0
    return {
        'threshold': int(threshold),
        'n': len(selected),
        'avg48': round(sum(outcomes) / len(outcomes), 3),
        'median48': round(median, 3),
        'win_rate': round(sum(1 for value in outcomes if value >= 1.0) / len(outcomes), 3),
        'bad_rate': round(sum(1 for value in outcomes if value <= -3.0) / len(outcomes), 3),
        'avg_mae': round(sum(float(row.get('mae48', 0) or 0) for row in selected) / len(selected), 3),
        'avg_mfe': round(sum(float(row.get('mfe48', 0) or 0) for row in selected) / len(selected), 3),
        'plan_expectancy': round(sum(plan_returns) / len(plan_returns), 3),
        'plan_win_rate': round(sum(1 for row in selected if row.get('plan_outcome') == 'target') / len(selected), 3),
        'plan_stop_rate': round(sum(1 for row in selected if row.get('plan_outcome') == 'stop') / len(selected), 3),
    }


def v191121_policy_match(row, policy):
    return (
        int(row.get('score', 0) or 0) >= int(policy.get('threshold', 70))
        and float(row.get('btc_24h', 0) or 0) >= float(policy.get('btc_min', -99))
        and float(row.get('ret_4h', 0) or 0) >= float(policy.get('ret4_min', -99))
        and float(row.get('ret_24h', 0) or 0) >= float(policy.get('ret24_min', -99))
        and float(row.get('ret_24h', 0) or 0) <= float(policy.get('ret24_max', 99))
        and float(row.get('rsi14', 50) or 50) <= float(policy.get('rsi_max', 100))
        and float(row.get('volume_ratio', 1) or 1) >= float(policy.get('volume_min', 0))
        and (not policy.get('above_ema_required') or bool(row.get('above_ema20')))
        and (not policy.get('btc_ema_required') or bool(row.get('btc_above_ema20')))
    )


def v191121_policy_metrics(samples, policy):
    selected = [row for row in samples if v191121_policy_match(row, policy)]
    metrics = v191120_metrics(selected, threshold=0)
    metrics['policy'] = dict(policy)
    metrics['threshold'] = int(policy.get('threshold', 70))
    return metrics


def v191121_policy_candidates():
    policies = []
    for threshold in [60, 65, 70, 75, 80]:
        for btc_min in [-1.0, 0.0, 0.5]:
            for ret4_min in [-1.0, 0.0]:
                for volume_min in [0.8, 1.0, 1.2]:
                    for rsi_max in [60, 66]:
                        for above_ema_required in [False, True]:
                            for btc_ema_required in [False, True]:
                                policies.append({
                                    'threshold': threshold,
                                    'btc_min': btc_min,
                                    'ret4_min': ret4_min,
                                    'ret24_min': -3.0,
                                    'ret24_max': 4.5,
                                    'volume_min': volume_min,
                                    'rsi_max': rsi_max,
                                    'above_ema_required': above_ema_required,
                                    'btc_ema_required': btc_ema_required,
                                })
    return policies


def v191121_policy_objective(metrics):
    return (
        float(metrics.get('avg48', 0) or 0) * 6
        + float(metrics.get('median48', 0) or 0) * 4
        + float(metrics.get('win_rate', 0) or 0) * 12
        + float(metrics.get('plan_expectancy', 0) or 0) * 12
        + float(metrics.get('plan_win_rate', 0) or 0) * 8
        - float(metrics.get('bad_rate', 0) or 0) * 28
        - float(metrics.get('plan_stop_rate', 0) or 0) * 8
        + min(2.0, float(metrics.get('n', 0) or 0) / 250.0)
    )


def v191120_bad_rate_value(metrics):
    try:
        value = (metrics or {}).get('bad_rate')
        return float(value) if value is not None else 1.0
    except Exception:
        return 1.0


V2000_REGIMES = ['growth', 'decline', 'sideways', 'panic', 'recovery']


def v2000_select_policy_for_rows(rows):
    if len(rows) < 60:
        return {}
    metrics = [v191121_policy_metrics(rows, policy) for policy in v191121_policy_candidates()]
    min_n = max(25, min(80, int(len(rows) * 0.08)))
    eligible = [item for item in metrics if int(item.get('n', 0) or 0) >= min_n]
    return max(eligible, key=v191121_policy_objective) if eligible else {}


def v2000_ensemble_selected_rows(rows, regime_experts):
    selected = []
    for row in rows:
        regime = str(row.get('regime') or v2000_market_regime(row))
        expert = regime_experts.get(regime, {}) if isinstance(regime_experts, dict) else {}
        policy = expert.get('policy', {}) if isinstance(expert, dict) else {}
        if policy and v191121_policy_match(row, policy):
            selected.append(row)
    return selected


def v2000_build_regime_experts(train, validation):
    experts = {}
    for regime in V2000_REGIMES:
        train_rows = [row for row in train if str(row.get('regime')) == regime]
        validation_rows = [row for row in validation if str(row.get('regime')) == regime]
        selected_train = v2000_select_policy_for_rows(train_rows)
        policy = selected_train.get('policy', {}) if isinstance(selected_train, dict) else {}
        selected_validation = v191121_policy_metrics(validation_rows, policy) if policy else {}
        experts[regime] = {
            'train_rows': len(train_rows),
            'validation_rows': len(validation_rows),
            'policy': policy,
            'train': selected_train,
            'validation': selected_validation,
        }
    combined_train = v2000_ensemble_selected_rows(train, experts)
    combined_validation = v2000_ensemble_selected_rows(validation, experts)
    return {
        'experts': experts,
        'train': v191120_metrics(combined_train, 0),
        'validation': v191120_metrics(combined_validation, 0),
    }


def v2000_validation_windows(validation, regime_experts, window_count=3):
    timestamps = sorted({int(row.get('ts', 0) or 0) for row in validation})
    if not timestamps:
        return []
    windows = []
    total = len(timestamps)
    for index in range(int(window_count)):
        start_pos = int(total * index / window_count)
        end_pos = int(total * (index + 1) / window_count)
        window_ts = set(timestamps[start_pos:end_pos])
        rows = [row for row in validation if int(row.get('ts', 0) or 0) in window_ts]
        selected = v2000_ensemble_selected_rows(rows, regime_experts)
        metrics = v191120_metrics(selected, 0)
        metrics['window'] = index + 1
        metrics['stable'] = (
            int(metrics.get('n', 0) or 0) >= 15
            and float(metrics.get('plan_expectancy', 0) or 0) > 0
            and v191120_bad_rate_value(metrics) <= 0.25
        )
        windows.append(metrics)
    return windows


def v191123_validation_windows(validation, policy, window_count=3):
    timestamps = sorted({int(row.get('ts', 0) or 0) for row in validation})
    if not timestamps or not policy:
        return []
    windows = []
    total = len(timestamps)
    for index in range(int(window_count)):
        start_pos = int(total * index / window_count)
        end_pos = int(total * (index + 1) / window_count)
        window_ts = set(timestamps[start_pos:end_pos])
        rows = [row for row in validation if int(row.get('ts', 0) or 0) in window_ts]
        metrics = v191121_policy_metrics(rows, policy)
        metrics['window'] = index + 1
        metrics['stable'] = (
            int(metrics.get('n', 0) or 0) >= 15
            and float(metrics.get('plan_expectancy', 0) or 0) > 0
            and v191120_bad_rate_value(metrics) <= 0.25
        )
        windows.append(metrics)
    return windows


def v2022_policy_readiness(validation_metrics, windows):
    validation_metrics = validation_metrics if isinstance(validation_metrics, dict) else {}
    windows = windows if isinstance(windows, list) else []
    stable_windows = sum(1 for row in windows if isinstance(row, dict) and row.get('stable'))
    checks = {
        'validation_n_60': int(validation_metrics.get('n', 0) or 0) >= 60,
        'validation_avg_positive': float(validation_metrics.get('avg48', 0) or 0) >= 0.4,
        'validation_win_rate': float(validation_metrics.get('win_rate', 0) or 0) >= 0.52,
        'validation_bad_rate': v191120_bad_rate_value(validation_metrics) <= 0.25,
        'validation_plan_expectancy': float(validation_metrics.get('plan_expectancy', 0) or 0) >= 0.20,
        'validation_window_stability': len(windows) == 3 and stable_windows == 3,
    }
    passed = sum(1 for ok in checks.values() if ok)
    qualified = (
        passed >= 5
        and int(validation_metrics.get('n', 0) or 0) >= 60
        and stable_windows == 3
    )
    strength = (
        passed * 100
        + stable_windows * 20
        + float(validation_metrics.get('avg48', 0) or 0) * 8
        + float(validation_metrics.get('plan_expectancy', 0) or 0) * 12
        - float(validation_metrics.get('bad_rate', 0) or 0) * 30
        + min(2.0, int(validation_metrics.get('n', 0) or 0) / 100.0)
    )
    return {
        'checks': checks,
        'passed': passed,
        'stable_windows': stable_windows,
        'qualified': qualified,
        'strength': round(strength, 3),
    }


def v2022_evaluate_deployment_policy(name, policy, train, validation):
    if not isinstance(policy, dict) or not policy:
        return {}
    train_metrics = v191121_policy_metrics(train, policy)
    validation_metrics = v191121_policy_metrics(validation, policy)
    windows = v191123_validation_windows(validation, policy, window_count=3)
    readiness = v2022_policy_readiness(validation_metrics, windows)
    return {
        'name': name,
        'policy': dict(policy),
        'train': train_metrics,
        'validation': validation_metrics,
        'windows': windows,
        **readiness,
    }


def v2023_recovery_policies():
    rows = []
    for above_ema in [False, True]:
        for btc_ema in [False, True]:
            policy = dict(V2022_BASELINE_POLICY)
            policy['above_ema_required'] = above_ema
            policy['btc_ema_required'] = btc_ema
            rows.append((
                f"recovery_ema{int(above_ema)}_btc{int(btc_ema)}",
                policy,
            ))
    return rows


def v2023_load_champion():
    try:
        data = load_json(V2023_CHAMPION_FILE)
        return data if isinstance(data, dict) else {}
    except Exception:
        return {}


def v2023_save_champion(result):
    if not isinstance(result, dict):
        return False
    readiness = v2022_policy_readiness(
        result.get('selected_validation', {}),
        result.get('validation_windows', []),
    )
    policy = result.get('selected_policy', {}) if isinstance(result.get('selected_policy', {}), dict) else {}
    if not readiness.get('qualified') or not policy:
        return False
    payload = {
        'qualified': True,
        'saved_at': time.time(),
        'source_version': V191111_VERSION,
        'policy_schema': V202_POLICY_SCHEMA,
        'policy': dict(policy),
        'train': result.get('selected_train', {}),
        'validation': result.get('selected_validation', {}),
        'validation_windows': result.get('validation_windows', []),
        'readiness_checks': readiness.get('checks', {}),
        'readiness_passed': readiness.get('passed', 0),
        'stable_windows': readiness.get('stable_windows', 0),
        'strength': readiness.get('strength', 0),
    }
    save_json(V2023_CHAMPION_FILE, payload)
    try:
        mark_github_dirty(V2023_CHAMPION_FILE)
    except Exception:
        pass
    return True


def v2024_fast_recovery_result(candles_by_asset, samples, train, validation, incumbent_lab):
    evaluations = [
        v2022_evaluate_deployment_policy(name, policy, train, validation)
        for name, policy in v2023_recovery_policies()
    ]
    qualified = [row for row in evaluations if isinstance(row, dict) and row.get('qualified')]
    if not qualified:
        return {}
    retained = max(qualified, key=lambda row: float(row.get('strength', 0) or 0))
    policy = retained.get('policy', {})
    checks = retained.get('checks', {})
    windows = retained.get('windows', [])
    validation_metrics = retained.get('validation', {})
    timestamps = sorted({int(row.get('ts', 0) or 0) for row in samples})
    split_ts = timestamps[int(len(timestamps) * 0.70)] if timestamps else 0
    previous_validation = (
        incumbent_lab.get('selected_validation', {})
        if isinstance(incumbent_lab, dict) and isinstance(incumbent_lab.get('selected_validation', {}), dict)
        else {}
    )
    return {
        'version': V191111_VERSION,
        'policy_schema': V202_POLICY_SCHEMA,
        'updated_at': time.time(),
        'updated_at_iso': datetime.utcnow().isoformat(),
        'method': 'fast atomic recovery of four pre-registered champion configurations',
        'assets_requested': list(V191120_ENTRY_LAB_ASSETS),
        'assets_loaded': [asset for asset, rows in candles_by_asset.items() if asset != 'BTC' and len(rows) >= 60],
        'candle_counts': {asset: len(rows) for asset, rows in candles_by_asset.items()},
        'total_samples': len(samples),
        'train_samples': len(train),
        'validation_samples': len(validation),
        'split_ts': split_ts,
        'train_thresholds': [],
        'validation_thresholds': [],
        'selected_threshold': int(policy.get('threshold', 80) or 80),
        'selected_train': retained.get('train', {}),
        'selected_validation': validation_metrics,
        'selected_policy': policy,
        'policy_mode': 'global_policy',
        'global_train': retained.get('train', {}),
        'global_validation': validation_metrics,
        'global_validation_windows': windows,
        'regime_experts': incumbent_lab.get('regime_experts', {}) if isinstance(incumbent_lab, dict) else {},
        'regime_train': {},
        'regime_validation': {},
        'regime_candidate': False,
        'regime_validation_approved': False,
        'policy_search_count': 4,
        'validation_windows': windows,
        'stable_windows': int(retained.get('stable_windows', 0) or 0),
        'readiness_checks': checks,
        'readiness_passed': int(retained.get('passed', 0) or 0),
        'ready_for_live': False,
        'champion_retained': True,
        'champion_source': retained.get('name'),
        'champion_strength': retained.get('strength'),
        'deployment_guard': 'fast recovery completed; weaker research candidate rejected',
        'research_candidate': {
            'validation': previous_validation,
            'readiness_passed': int(incumbent_lab.get('readiness_passed', 0) or 0) if isinstance(incumbent_lab, dict) else 0,
            'reason': 'previous weak candidate retained only for audit',
        },
        'note': 'Recovered PAPER champion only. Live BUY and autotrading remain disabled.',
    }


def v191120_run_walkforward(candles_by_asset=None):
    incumbent_lab = v191120_load_entry_lab()
    if candles_by_asset is None:
        candles_by_asset = {'BTC': v191120_fetch_4h_candles('BTC')}
        for asset in V191120_ENTRY_LAB_ASSETS:
            candles_by_asset[asset] = v191120_fetch_4h_candles(asset)
    samples = v191120_build_dataset(candles_by_asset)
    timestamps = sorted({int(row['ts']) for row in samples})
    split_ts = timestamps[int(len(timestamps) * 0.70)] if timestamps else 0
    train = [row for row in samples if int(row['ts']) <= split_ts]
    validation = [row for row in samples if int(row['ts']) > split_ts]
    stored_champion = v2023_load_champion()
    if not v202_entry_lab_compatible(incumbent_lab) and not stored_champion.get('qualified'):
        recovery = v2024_fast_recovery_result(candles_by_asset, samples, train, validation, incumbent_lab)
        if recovery:
            save_json(V191120_ENTRY_LAB_FILE, recovery)
            v2023_save_champion(recovery)
            try:
                background_github_sync(
                    [V191120_ENTRY_LAB_FILE, V2023_CHAMPION_FILE, CHAT_ID_FILE],
                    max_files=3,
                )
            except Exception:
                pass
            return recovery
        failed = dict(incumbent_lab) if isinstance(incumbent_lab, dict) else {}
        failed.update({
            'version': V191111_VERSION,
            'policy_schema': V202_POLICY_SCHEMA,
            'recovery_attempt_at': time.time(),
            'recovery_error': 'none of four pre-registered champion configurations passed 5/6 and 3/3',
            'recovery_running': False,
        })
        save_json(V191120_ENTRY_LAB_FILE, failed)
        return failed
    thresholds = [55, 60, 65, 70, 75]
    train_metrics = [v191120_metrics(train, threshold) for threshold in thresholds]
    valid_metrics = [v191120_metrics(validation, threshold) for threshold in thresholds]
    eligible = [row for row in train_metrics if int(row.get('n', 0)) >= 40]
    def objective(row):
        return (
            float(row.get('avg48', 0)) * 8
            + float(row.get('win_rate', 0)) * 20
            - float(row.get('bad_rate', 0)) * 30
        )
    selected_train = max(eligible, key=objective) if eligible else (max(train_metrics, key=lambda row: row.get('n', 0)) if train_metrics else {})
    selected_threshold = int(selected_train.get('threshold', 70) or 70)
    selected_validation = next((row for row in valid_metrics if row.get('threshold') == selected_threshold), {})

    policy_train_rows = [
        v191121_policy_metrics(train, policy)
        for policy in v191121_policy_candidates()
    ]
    policy_eligible = [row for row in policy_train_rows if int(row.get('n', 0) or 0) >= 80]
    selected_policy_train = (
        max(policy_eligible, key=v191121_policy_objective)
        if policy_eligible else {}
    )
    selected_policy = selected_policy_train.get('policy', {}) if isinstance(selected_policy_train, dict) else {}
    selected_policy_validation = (
        v191121_policy_metrics(validation, selected_policy)
        if selected_policy else {}
    )
    if selected_policy:
        selected_threshold = int(selected_policy.get('threshold', selected_threshold) or selected_threshold)
        selected_train = selected_policy_train
        selected_validation = selected_policy_validation
    global_train = dict(selected_train) if isinstance(selected_train, dict) else {}
    global_validation = dict(selected_validation) if isinstance(selected_validation, dict) else {}
    global_validation_windows = v191123_validation_windows(validation, selected_policy, window_count=3)
    regime_result = v2000_build_regime_experts(train, validation)
    regime_train = regime_result.get('train', {}) if isinstance(regime_result, dict) else {}
    regime_validation = regime_result.get('validation', {}) if isinstance(regime_result, dict) else {}
    regime_experts = regime_result.get('experts', {}) if isinstance(regime_result, dict) else {}
    regime_candidate = (
        int(regime_train.get('n', 0) or 0) >= 80
        and v191121_policy_objective(regime_train) >= v191121_policy_objective(selected_train) + 0.30
    )
    regime_validation_windows = v2000_validation_windows(validation, regime_experts, window_count=3)
    regime_validation_approved = (
        regime_candidate
        and int(regime_validation.get('n', 0) or 0) >= 60
        and float(regime_validation.get('avg48', 0) or 0) >= 0.40
        and float(regime_validation.get('plan_expectancy', 0) or 0) >= 0.20
        and v191120_bad_rate_value(regime_validation) <= 0.25
        and len(regime_validation_windows) == 3
        and all(bool(row.get('stable')) for row in regime_validation_windows)
    )
    regime_active = bool(regime_candidate and regime_validation_approved)
    if regime_active:
        selected_train = regime_train
        selected_validation = regime_validation
        validation_windows = regime_validation_windows
    else:
        selected_train = global_train
        selected_validation = global_validation
        validation_windows = global_validation_windows
    stable_windows = sum(1 for row in validation_windows if row.get('stable'))
    readiness_checks = {
        'validation_n_60': int(selected_validation.get('n', 0) or 0) >= 60,
        'validation_avg_positive': float(selected_validation.get('avg48', 0) or 0) >= 0.4,
        'validation_win_rate': float(selected_validation.get('win_rate', 0) or 0) >= 0.52,
        'validation_bad_rate': v191120_bad_rate_value(selected_validation) <= 0.25,
        'validation_plan_expectancy': float(selected_validation.get('plan_expectancy', 0) or 0) >= 0.20,
        'validation_window_stability': len(validation_windows) == 3 and stable_windows == 3,
    }
    result = {
        'version': V191111_VERSION,
        'policy_schema': V202_POLICY_SCHEMA,
        'updated_at': time.time(),
        'updated_at_iso': datetime.utcnow().isoformat(),
        'method': '4h chronological walk-forward 70/30; features use past candles only; stride 12h',
        'assets_requested': list(V191120_ENTRY_LAB_ASSETS),
        'assets_loaded': [asset for asset, rows in candles_by_asset.items() if asset != 'BTC' and len(rows) >= 60],
        'candle_counts': {asset: len(rows) for asset, rows in candles_by_asset.items()},
        'total_samples': len(samples),
        'train_samples': len(train),
        'validation_samples': len(validation),
        'split_ts': split_ts,
        'train_thresholds': train_metrics,
        'validation_thresholds': valid_metrics,
        'selected_threshold': selected_threshold,
        'selected_train': selected_train,
        'selected_validation': selected_validation,
        'selected_policy': selected_policy,
        'policy_mode': 'regime_experts' if regime_active else 'global_policy',
        'regime_candidate': bool(regime_candidate),
        'regime_validation_approved': bool(regime_validation_approved),
        'regime_rejection_reason': (
            ''
            if regime_active or not regime_candidate
            else 'independent validation or one of three windows failed; global policy retained'
        ),
        'global_train': global_train,
        'global_validation': global_validation,
        'global_validation_windows': global_validation_windows,
        'regime_experts': regime_experts,
        'regime_train': regime_train,
        'regime_validation': regime_validation,
        'policy_search_count': len(policy_train_rows),
        'validation_windows': validation_windows,
        'stable_windows': stable_windows,
        'readiness_checks': readiness_checks,
        'readiness_passed': sum(1 for value in readiness_checks.values() if value),
        'ready_for_live': False,
        'note': 'Historical validation only. It cannot enable live BUY or autotrading.',
    }

    current_readiness = v2022_policy_readiness(
        result.get('selected_validation', {}),
        result.get('validation_windows', []),
    )
    deployment_candidates = [
        v2022_evaluate_deployment_policy(name, policy, train, validation)
        for name, policy in v2023_recovery_policies()
    ]
    stored_champion = v2023_load_champion()
    stored_policy = (
        stored_champion.get('policy', {})
        if isinstance(stored_champion.get('policy', {}), dict)
        else {}
    )
    if stored_policy:
        deployment_candidates.append(
            v2022_evaluate_deployment_policy('stored_champion', stored_policy, train, validation)
        )
    incumbent_policy = (
        incumbent_lab.get('selected_policy', {})
        if isinstance(incumbent_lab, dict) and isinstance(incumbent_lab.get('selected_policy', {}), dict)
        else {}
    )
    if incumbent_policy:
        deployment_candidates.append(
            v2022_evaluate_deployment_policy('incumbent', incumbent_policy, train, validation)
        )
    qualified_candidates = [
        row for row in deployment_candidates
        if isinstance(row, dict) and row.get('qualified')
    ]
    retained = max(qualified_candidates, key=lambda row: float(row.get('strength', 0) or 0)) if qualified_candidates else {}
    if retained and (
        not current_readiness.get('qualified')
        or float(retained.get('strength', 0) or 0) > float(current_readiness.get('strength', 0) or 0) + 1.0
    ):
        result['research_candidate'] = {
            'policy_mode': result.get('policy_mode'),
            'policy': result.get('selected_policy', {}),
            'validation': result.get('selected_validation', {}),
            'validation_windows': result.get('validation_windows', []),
            'readiness_checks': result.get('readiness_checks', {}),
            'readiness_passed': result.get('readiness_passed', 0),
            'reason': 'candidate did not beat deployment champion',
        }
        result.update({
            'selected_threshold': int(retained.get('policy', {}).get('threshold', 80) or 80),
            'selected_train': retained.get('train', {}),
            'selected_validation': retained.get('validation', {}),
            'selected_policy': retained.get('policy', {}),
            'policy_mode': 'global_policy',
            'global_train': retained.get('train', {}),
            'global_validation': retained.get('validation', {}),
            'global_validation_windows': retained.get('windows', []),
            'validation_windows': retained.get('windows', []),
            'stable_windows': int(retained.get('stable_windows', 0) or 0),
            'readiness_checks': retained.get('checks', {}),
            'readiness_passed': int(retained.get('passed', 0) or 0),
            'champion_retained': True,
            'champion_source': retained.get('name'),
            'champion_strength': retained.get('strength'),
            'rejected_candidate_strength': current_readiness.get('strength'),
            'deployment_guard': 'stronger validated champion retained; weaker recalculation kept as research only',
        })
    else:
        result.update({
            'champion_retained': False,
            'champion_source': 'new_train_candidate',
            'champion_strength': current_readiness.get('strength'),
            'deployment_guard': 'new candidate passed retention guard',
        })

    save_json(V191120_ENTRY_LAB_FILE, result)
    v2023_save_champion(result)
    try:
        background_github_sync([V191120_ENTRY_LAB_FILE, CHAT_ID_FILE, LAST_UPDATE_FILE], max_files=3)
    except Exception:
        pass
    return result


def v191120_load_entry_lab():
    try:
        data = load_json(V191120_ENTRY_LAB_FILE)
        return data if isinstance(data, dict) else {}
    except Exception:
        return {}


def v202_entry_lab_compatible(data):
    if not isinstance(data, dict) or not data:
        return False
    schema_ok = str(data.get('policy_schema') or '') == V202_POLICY_SCHEMA
    legacy_ok = str(data.get('version') or '') == 'v20.1.2 FRESHNESS & FORWARD RACE GUARD'
    if not (schema_ok or legacy_ok):
        return False
    checks = data.get('readiness_checks', {}) if isinstance(data.get('readiness_checks', {}), dict) else {}
    validation = data.get('selected_validation', {}) if isinstance(data.get('selected_validation', {}), dict) else {}
    return (
        str(data.get('policy_mode') or '') == 'global_policy'
        and int(data.get('stable_windows', 0) or 0) == 3
        and sum(1 for ok in checks.values() if ok) >= 5
        and int(validation.get('n', 0) or 0) >= 60
        and float(validation.get('plan_expectancy', 0) or 0) >= 0.20
        and v191120_bad_rate_value(validation) <= 0.25
    )


def v191120_entry_lab_lines():
    data = v191120_load_entry_lab()
    lines = ['🧪 WALK-FORWARD ENTRY LAB']
    if not data:
        return lines + ['• результат ещё не собран; фоновый replay запущен или ожидает запуска']
    lab_version = str(data.get('version') or '')
    lab_fresh = lab_version == V191111_VERSION
    lab_compatible = v202_entry_lab_compatible(data)
    if lab_fresh and not lab_compatible:
        lines += [
            '• статус: 🔴 текущий исследовательский результат отклонён и не используется',
            '• подтверждённая стратегия восстанавливается; live BUY остаётся OFF.',
        ]
    elif not lab_fresh and lab_compatible:
        lines += [
            f"• статус: ✅ validated carry-forward из {lab_version}; свежий пересчёт выполняется в фоне",
            '• policy разрешена только для PAPER Forward Lab; live BUY остаётся OFF.',
        ]
    elif not lab_fresh:
        lines += [
            f"• статус: ⏳ пересчёт выполняется; ниже cached результат {lab_version or 'неизвестной версии'}",
            '• cached policy не используется Forward Shadow и не записывается как эффективность новой версии.',
        ]
    if data.get('recovery_error'):
        lines.append(f"• recovery error: {data.get('recovery_error')}")
    validation = data.get('selected_validation', {}) if isinstance(data.get('selected_validation'), dict) else {}
    checks = data.get('readiness_checks', {}) if isinstance(data.get('readiness_checks'), dict) else {}
    policy = data.get('selected_policy', {}) if isinstance(data.get('selected_policy'), dict) else {}
    windows = data.get('validation_windows', []) if isinstance(data.get('validation_windows'), list) else []
    policy_mode = str(data.get('policy_mode') or 'global_policy')
    lines += [
        f"• samples: total {data.get('total_samples', 0)} | train {data.get('train_samples', 0)} | validation {data.get('validation_samples', 0)}",
        f"• assets loaded: {len(data.get('assets_loaded', []) or [])}/{len(data.get('assets_requested', []) or [])}",
        f"• history depth: up to {max((data.get('candle_counts', {}) or {'?': 0}).values())} candles per asset",
        f"• model: {'REGIME EXPERTS' if policy_mode == 'regime_experts' else 'GLOBAL POLICY'}"
        + (
            ''
            if lab_fresh and lab_compatible
            else (' (VALIDATED CARRY-FORWARD)' if lab_compatible else ' (REJECTED / NOT DEPLOYED)')
        ),
        f"• selected PAPER threshold: {data.get('selected_threshold', '?')}/100",
        (
            f"• policy: BTC ≥{float(policy.get('btc_min', 0) or 0):+.1f}% | 4ч ≥{float(policy.get('ret4_min', 0) or 0):+.1f}% | "
            f"volume ≥x{float(policy.get('volume_min', 0) or 0):.1f} | RSI ≤{int(policy.get('rsi_max', 0) or 0)}"
            if policy else "• policy: базовый score threshold"
        ),
        f"• validation: n {validation.get('n', 0)} | avg48 {float(validation.get('avg48', 0) or 0):+.2f}% | "
        f"win {float(validation.get('win_rate', 0) or 0)*100:.1f}% | bad {float(validation.get('bad_rate', 0) or 0)*100:.1f}% | "
        f"MAE {float(validation.get('avg_mae', 0) or 0):+.2f}%",
        f"• plan T1 +2% / stop -3%: expectancy {float(validation.get('plan_expectancy', 0) or 0):+.2f}% | "
        f"target {float(validation.get('plan_win_rate', 0) or 0)*100:.1f}% | stop {float(validation.get('plan_stop_rate', 0) or 0)*100:.1f}%",
        (
            "• validation windows: "
            + " | ".join(
                f"{int(row.get('window', 0))}: {float(row.get('plan_expectancy', 0) or 0):+.2f}% {'✅' if row.get('stable') else '❌'}"
                for row in windows
            )
            if windows else "• validation windows: расчёт ожидается"
        ),
        f"• historical checks: {sum(1 for value in checks.values() if value)}/{len(checks)} | live BUY: ALWAYS OFF",
        '• threshold is research-only until paper/live-forward results confirm it.',
    ]
    if data.get('regime_candidate') and not data.get('regime_validation_approved'):
        lines.append('• regime experts: validation guard rejected deployment; stable GLOBAL POLICY retained.')
    if data.get('champion_retained'):
        research = data.get('research_candidate', {}) if isinstance(data.get('research_candidate', {}), dict) else {}
        lines.append(
            f"• champion retention: stronger policy retained from {data.get('champion_source')} | "
            f"rejected candidate checks {research.get('readiness_passed', 0)}/6"
        )
    experts = data.get('regime_experts', {}) if isinstance(data.get('regime_experts'), dict) else {}
    if experts:
        lines.append('• regime experts:')
        for regime in V2000_REGIMES:
            expert = experts.get(regime, {}) if isinstance(experts.get(regime), dict) else {}
            validation_row = expert.get('validation', {}) if isinstance(expert.get('validation'), dict) else {}
            policy_row = expert.get('policy', {}) if isinstance(expert.get('policy'), dict) else {}
            lines.append(
                f"  - {regime}: threshold {policy_row.get('threshold', '—')} | n {validation_row.get('n', 0)} | "
                f"exp {float(validation_row.get('plan_expectancy', 0) or 0):+.2f}% | bad {float(validation_row.get('bad_rate', 0) or 0)*100:.1f}%"
            )
    return lines


def v2000_policy_for_live(lab, feature):
    mode = str((lab or {}).get('policy_mode') or 'global_policy')
    if mode == 'regime_experts':
        regime = str(feature.get('regime') or v2000_market_regime(feature))
        experts = lab.get('regime_experts', {}) if isinstance(lab.get('regime_experts'), dict) else {}
        expert = experts.get(regime, {}) if isinstance(experts.get(regime), dict) else {}
        policy = expert.get('policy', {}) if isinstance(expert.get('policy'), dict) else {}
        if policy:
            return policy, regime
    policy = lab.get('selected_policy', {}) if isinstance(lab.get('selected_policy'), dict) else {}
    return policy, str(feature.get('regime') or v2000_market_regime(feature))


def v191120_maybe_run_background(force=False):
    global V191120_ENTRY_LAB_LAST_START
    if V20251_BENCHMARK_FREEZE:
        return False
    now = time.time()
    if not force:
        data = v191120_load_entry_lab()
        updated = float(data.get('updated_at', 0) or 0) if isinstance(data, dict) else 0
        same_version = str(data.get('version') or '') == V191111_VERSION if isinstance(data, dict) else False
        if updated and same_version and v202_entry_lab_compatible(data) and now - updated < 24 * 3600:
            return False
        if now - float(V191120_ENTRY_LAB_LAST_START or 0) < 3600:
            return False
    V191120_ENTRY_LAB_LAST_START = now

    def worker():
        acquired = V191120_ENTRY_LAB_LOCK.acquire(False)
        if not acquired:
            return
        completed = False
        try:
            v191120_run_walkforward()
            completed = True
        except Exception as exc:
            print(f"walk-forward entry lab error: {exc}")
        finally:
            V191120_ENTRY_LAB_LOCK.release()
        if completed and 'v191124_maybe_forward_background' in globals():
            try:
                v191124_maybe_forward_background(force=True)
            except Exception as exc:
                print(f"post-lab forward shadow error: {exc}")

    try:
        Thread(target=worker, daemon=True).start()
        return True
    except Exception:
        return False


def v191120_learn_fast_report(start=False):
    if V20251_BENCHMARK_FREEZE:
        return '\n'.join([
            '🧠 Ускоренное обучение',
            f'Версия: {v2021_user_version()}',
            '',
            'Состояние: старый исторический расчёт остановлен.',
            'Причина: прежняя оценка не воспроизводится на повторной проверке.',
            '',
            'Следующий этап: единый фиксированный исторический эталон для всех версий.',
            'Реальные покупки и автоторговля выключены.',
            '',
            'Полные технические данные: /audit_file',
        ])
    old_started = False
    try:
        old_started = maybe_run_backtest_background(force=bool(start))
    except Exception:
        pass
    lab_started = v191120_maybe_run_background(force=bool(start))
    try:
        forward_started = v191124_maybe_forward_background(force=bool(start))
    except Exception:
        forward_started = False
    lab = v191120_load_entry_lab()
    checks = lab.get('readiness_checks', {}) if isinstance(lab.get('readiness_checks', {}), dict) else {}
    windows = lab.get('validation_windows', []) if isinstance(lab.get('validation_windows', []), list) else []
    validation = lab.get('selected_validation', {}) if isinstance(lab.get('selected_validation', {}), dict) else {}
    forward_lab = v202_forward_lab_load() if 'v202_forward_lab_load' in globals() else {}
    experiments_open = forward_lab.get('open', {}) if isinstance(forward_lab.get('open', {}), dict) else {}
    experiments_closed = forward_lab.get('closed', []) if isinstance(forward_lab.get('closed', []), list) else []
    passed = sum(1 for ok in checks.values() if ok)
    stable = sum(1 for row in windows if isinstance(row, dict) and row.get('stable'))
    compatible = v202_entry_lab_compatible(lab)
    lines = ['🧠 Ускоренное обучение', f'Версия: {v2021_user_version()}', '']
    if compatible:
        lines += [
            f"Состояние: {'идёт контрольный пересчёт; подтверждённая стратегия сохранена' if lab_started else 'расчёт актуален'}",
            f"Историческая проверка: {passed}/{len(checks) if checks else 0}",
            f"Стабильные периоды: {stable}/{len(windows) if windows else 0}",
            f"Средний результат через 48 часов: {float(validation.get('avg48', 0) or 0):+.2f}%",
            f"Ожидаемый результат торгового плана: {float(validation.get('plan_expectancy', 0) or 0):+.2f}%",
        ]
    else:
        if lab.get('recovery_error'):
            lines += [
                'Состояние: восстановление завершилось без подходящей стратегии',
                'Предыдущий результат 5/6 не повторился и больше не считается подтверждённым.',
                'Слабый вариант 1/6 отклонён и не используется.',
                'Причина записана в техническом отчёте.',
            ]
        else:
            lines += [
                'Состояние: идёт восстановление подтверждённой стратегии',
                'Последний подтверждённый результат: 5/6, стабильные периоды 3/3',
                f'Слабый новый вариант: {passed}/{len(checks) if checks else 6} — отклонён и не используется',
            ]
    lines += [
        '',
        f"Новые независимые тесты: открыто {len(experiments_open)} | завершено {len(experiments_closed)}",
        '',
        'Вывод: слабый расчёт не используется. Бот работает только с подтверждённой виртуальной стратегией.',
        'Реальные покупки и автоторговля выключены.',
        '',
        'Полные технические данные: /audit_file',
    ]
    return '\n'.join(lines)


def v202_forward_lab_load():
    try:
        data = load_json(V202_FORWARD_LAB_FILE)
        if not isinstance(data, dict):
            data = {}
    except Exception:
        data = {}
    data.setdefault('open', {})
    data.setdefault('closed', [])
    return data


def v202_forward_lab_save(data):
    if not isinstance(data, dict):
        return
    data['version'] = V191111_VERSION
    save_json(V202_FORWARD_LAB_FILE, data)
    try:
        mark_github_dirty(V202_FORWARD_LAB_FILE)
    except Exception:
        pass


def v202_challenger_policies(champion):
    champion = dict(champion or {})
    if not champion:
        return {}
    balanced = dict(champion)
    balanced.update({
        'threshold': max(65, int(champion.get('threshold', 80) or 80) - 5),
        'btc_min': min(float(champion.get('btc_min', 0) or 0), -0.5),
        'ret4_min': min(float(champion.get('ret4_min', -1) or -1), -1.5),
        'volume_min': min(float(champion.get('volume_min', 1) or 1), 0.8),
        'rsi_max': max(float(champion.get('rsi_max', 60) or 60), 66),
    })
    exploration = dict(champion)
    exploration.update({
        'threshold': max(60, int(champion.get('threshold', 80) or 80) - 15),
        'btc_min': -1.0,
        'ret4_min': -2.0,
        'volume_min': 0.7,
        'rsi_max': 70,
        'above_ema_required': False,
        'btc_ema_required': False,
    })
    return {
        'balanced': balanced,
        'exploration': exploration,
    }


def v202_forward_lab_cycle(features_by_asset, lab):
    result = {'updated': 0, 'closed': 0, 'created': 0, 'matches': {}, 'active': 0}
    if not V202_FORWARD_LAB_LOCK.acquire(False):
        result['error'] = 'cycle already running'
        return result
    try:
        data = v202_forward_lab_load()
        open_rows = data.get('open', {}) if isinstance(data.get('open', {}), dict) else {}
        closed_rows = data.get('closed', []) if isinstance(data.get('closed', []), list) else []
        now = time.time()

        for key, trade in list(open_rows.items()):
            if not isinstance(trade, dict):
                open_rows.pop(key, None)
                continue
            feature = features_by_asset.get(str(trade.get('asset') or '').upper())
            price = float((feature or {}).get('price', 0) or 0)
            entry = float(trade.get('entry_price', 0) or 0)
            entry_time = float(trade.get('entry_time', 0) or 0)
            if price <= 0 or entry <= 0 or entry_time <= 0:
                continue
            age_h = max(0.0, (now - entry_time) / 3600.0)
            pct = round(v191120_pct(entry, price), 3)
            trade['last_price'] = price
            trade['last_pct'] = pct
            trade['last_update_at'] = now
            results = trade.setdefault('results', {})
            for name, hours in [('1h', 1), ('4h', 4), ('12h', 12), ('24h', 24), ('48h', 48)]:
                if age_h >= hours and name not in results:
                    results[name] = pct
                    result['updated'] += 1
            if age_h >= 48:
                trade['status'] = 'closed'
                trade['closed_at'] = now
                trade['final_pct'] = float(results.get('48h', pct) or pct)
                closed_rows.append(trade)
                open_rows.pop(key, None)
                result['closed'] += 1

        champion = lab.get('selected_policy', {}) if isinstance(lab.get('selected_policy'), dict) else {}
        policies = v202_challenger_policies(champion)
        known_keys = set(open_rows)
        known_keys.update(str(row.get('id') or '') for row in closed_rows if isinstance(row, dict))
        active_by_cohort = {}
        active_assets = {}
        for trade in open_rows.values():
            if not isinstance(trade, dict):
                continue
            cohort = str(trade.get('cohort') or '')
            active_by_cohort[cohort] = active_by_cohort.get(cohort, 0) + 1
            active_assets.setdefault(cohort, set()).add(str(trade.get('asset') or '').upper())

        for cohort, policy in policies.items():
            matches = [
                feature for feature in features_by_asset.values()
                if isinstance(feature, dict) and v191121_policy_match(feature, policy)
            ]
            result['matches'][cohort] = len(matches)
            for feature in sorted(matches, key=lambda row: int(row.get('score', 0) or 0), reverse=True):
                if result['created'] >= 4 or active_by_cohort.get(cohort, 0) >= 4:
                    break
                asset = str(feature.get('asset') or '').upper()
                candle_ts = int(feature.get('ts', 0) or 0)
                price = float(feature.get('price', 0) or 0)
                key = f"{cohort}:{asset}:{candle_ts}"
                if not asset or price <= 0 or key in known_keys or asset in active_assets.get(cohort, set()):
                    continue
                trade = {
                    'id': key,
                    'cohort': cohort,
                    'asset': asset,
                    'entry_time': now,
                    'entry_price': price,
                    'last_price': price,
                    'last_pct': 0.0,
                    'status': 'open',
                    'policy': dict(policy),
                    'entry_features': dict(feature),
                    'results': {},
                    'created_by': V191111_VERSION,
                    'note': 'Experimental forward PAPER only; excluded from main gate and live BUY.',
                }
                open_rows[key] = trade
                known_keys.add(key)
                active_assets.setdefault(cohort, set()).add(asset)
                active_by_cohort[cohort] = active_by_cohort.get(cohort, 0) + 1
                result['created'] += 1

        result['active'] = len(open_rows)
        data['open'] = open_rows
        data['closed'] = closed_rows[-300:]
        data['last_cycle_at'] = now
        data['last_cycle_result'] = dict(result)
        data['policy_source_version'] = str(lab.get('version') or '')
        v202_forward_lab_save(data)
        return result
    except Exception as exc:
        result['error'] = str(exc)[:180]
        return result
    finally:
        V202_FORWARD_LAB_LOCK.release()


def v202_forward_lab_lines():
    data = v202_forward_lab_load()
    open_rows = data.get('open', {}) if isinstance(data.get('open', {}), dict) else {}
    closed_rows = data.get('closed', []) if isinstance(data.get('closed', []), list) else []
    last = data.get('last_cycle_result', {}) if isinstance(data.get('last_cycle_result', {}), dict) else {}
    lines = [
        '🧬 CHAMPION–CHALLENGER FORWARD LAB',
        '• основной champion не ослабляется; challengers существуют только как отдельные PAPER-эксперименты.',
        f"• last cycle: matches {last.get('matches', {})} | created {last.get('created', 0)} | updated {last.get('updated', 0)}",
        f"• active experiments: {len(open_rows)} | completed 48h: {len(closed_rows)} | real BUY: 0",
    ]
    for cohort in ['balanced', 'exploration', V206_FORWARD_COHORT]:
        active = [row for row in open_rows.values() if isinstance(row, dict) and row.get('cohort') == cohort]
        closed = [row for row in closed_rows if isinstance(row, dict) and row.get('cohort') == cohort]
        values = [float(row.get('final_pct', 0) or 0) for row in closed]
        avg = sum(values) / len(values) if values else 0.0
        positive = sum(1 for value in values if value > 0)
        lines.append(
            f"• {cohort}: active {len(active)} | closed {len(closed)} | "
            f"avg48 {avg:+.2f}% | positive {positive}/{len(values)}"
        )
    lines.append('• challengers не влияют на эффективность и веса до достаточной независимой выборки.')
    return lines


def v191124_forward_shadow_rows(data=None):
    try:
        data = data if isinstance(data, dict) else paper_store()
        open_trades = data.get('open', {}) if isinstance(data.get('open', {}), dict) else {}
        return [
            trade for trade in open_trades.values()
            if isinstance(trade, dict) and str(trade.get('virtual_type') or '') == V191124_FORWARD_TYPE
        ]
    except Exception:
        return []


def v191124_run_forward_shadow_scan():
    result = {'scanned': 0, 'matched': 0, 'created': 0, 'active': 0, 'error': ''}
    try:
        lab = v191120_load_entry_lab()
        if not v202_entry_lab_compatible(lab):
            result['error'] = 'entry lab belongs to previous version; wait for current recalculation'
            return result
        policy = lab.get('selected_policy', {}) if isinstance(lab.get('selected_policy'), dict) else {}
        regime_experts = lab.get('regime_experts', {}) if isinstance(lab.get('regime_experts'), dict) else {}
        checks = lab.get('readiness_checks', {}) if isinstance(lab.get('readiness_checks'), dict) else {}
        if (not policy and not regime_experts) or int(lab.get('stable_windows', 0) or 0) < 3:
            result['error'] = 'validated policy not ready'
            return result
        if sum(1 for value in checks.values() if value) < max(4, len(checks) - 1):
            result['error'] = 'historical checks insufficient'
            return result

        btc = v191120_fetch_4h_candles('BTC', pages=1, bars_per_page=90)
        btc_features = v191120_btc_features(btc)
        data = paper_store()
        open_trades = data.get('open', {}) if isinstance(data.get('open', {}), dict) else {}
        active = v191124_forward_shadow_rows(data)
        active_assets = {v19119_trade_asset(trade) for trade in active}
        now = time.time()
        created = []
        matches = []
        features_by_asset = {}
        for asset in V191120_ENTRY_LAB_ASSETS:
            candles = v191120_fetch_4h_candles(asset, pages=1, bars_per_page=90)
            if len(candles) < 40:
                continue
            result['scanned'] += 1
            feature = v191120_feature_score(candles, len(candles) - 1, btc_features)
            feature.update({'asset': asset, 'ts': candles[-1]['ts'], 'price': float(candles[-1]['close'])})
            features_by_asset[asset] = feature
            live_policy, regime = v2000_policy_for_live(lab, feature)
            if not live_policy or not v191121_policy_match(feature, live_policy):
                continue
            matches.append(feature)
            if asset in active_assets or len(active) + len(created) >= 4 or len(created) >= 2:
                continue
            price = float(candles[-1]['close'])
            key = paper_trade_key(asset, V191124_FORWARD_TYPE, now)
            trade = {
                'id': key,
                'asset': asset,
                'entry_time': now,
                'entry_price': price,
                'last_price': price,
                'last_pct': 0.0,
                'score': int(feature.get('score', 0) or 0),
                'entry_score': int(feature.get('score', 0) or 0),
                'virtual_type': V191124_FORWARD_TYPE,
                'source_action': 'VALIDATED_POLICY_PAPER_BUY',
                'is_quality': True,
                'is_policy_forward_shadow': True,
                'entry_plan': {
                    'target1': round(price * 1.02, 10),
                    'stop': round(price * 0.97, 10),
                    'target1_pct': 2.0,
                    'stop_pct': -3.0,
                },
                'policy': dict(live_policy),
                'market_regime': regime,
                'policy_mode': lab.get('policy_mode', 'global_policy'),
                'walkforward_validation': lab.get('selected_validation', {}),
                'entry_features': feature,
                'results': {},
                'result_details': {},
                'status': 'open',
                'note': 'Forward PAPER shadow only. Real money 0; autotrading OFF.',
                'created_by': V191111_VERSION,
            }
            open_trades[key] = trade
            created.append(trade)
            active_assets.add(asset)
        challenger_result = v202_forward_lab_cycle(features_by_asset, lab)
        if created:
            data['open'] = open_trades
        data['last_policy_forward_scan_at'] = now
        data['last_policy_forward_scan_result'] = {
            'scanned': result['scanned'],
            'matched': len(matches),
            'created': len(created),
            'version': V191111_VERSION,
            'challenger': challenger_result,
        }
        save_paper_store(data, sync=False)
        result.update({'matched': len(matches), 'created': len(created), 'active': len(active) + len(created)})
    except Exception as exc:
        result['error'] = str(exc)[:180]
    return result


