V206_FORWARD_LOCK = Lock()
V206_FORWARD_LAST_START = 0
V206_FORWARD_COHORT = 'adaptive_context_v206'


def v206_live_feature(asset, candles, btc_features):
    if len(candles) < 40:
        return {}
    index = len(candles) - 1
    feature = v191120_feature_score(candles, index, btc_features)
    closes = [float(item['close']) for item in candles[:index + 1]]
    volumes = [float(item['volume']) for item in candles[:index + 1]]
    price = closes[-1]
    ema_now = v191120_ema(closes[-20:], 20)
    ema_before = v191120_ema(closes[-23:-3], 20) if len(closes) >= 23 else ema_now
    recent_changes = [
        v191120_pct(closes[pos - 1], closes[pos])
        for pos in range(max(1, len(closes) - 6), len(closes))
    ]
    recent_volume = sum(volumes[-3:]) / 3.0
    previous_volume = sum(volumes[-12:-3]) / 9.0 if len(volumes) >= 12 else recent_volume
    feature.update({
        'asset': str(asset).upper(),
        'ts': int(candles[-1]['ts']),
        'price': price,
        'momentum_12h': round(v191120_pct(closes[-4], price), 4),
        'momentum_48h': round(v191120_pct(closes[-13], price), 4),
        'ema_gap': round(v191120_pct(ema_now, price), 4),
        'ema_slope': round(v191120_pct(ema_before, ema_now), 4),
        'relative_24h': round(
            float(feature.get('ret_24h', 0) or 0) - float(feature.get('btc_24h', 0) or 0),
            4,
        ),
        'up_ratio_6': round(
            sum(1 for value in recent_changes if value > 0) / float(len(recent_changes) or 1),
            4,
        ),
        'volume_trend': round(
            recent_volume / previous_volume if previous_volume > 0 else 1.0,
            4,
        ),
    })
    return feature


def v206_policy_match(feature, policy):
    if not isinstance(feature, dict) or not isinstance(policy, dict):
        return False
    return (
        float(feature.get('evidence_score') if feature.get('evidence_score') is not None else -999)
        >= float(policy.get('cutoff', 999))
        and float(feature.get('bad_probability') if feature.get('bad_probability') is not None else 1)
        <= float(policy.get('bad_max', 0))
        and float(feature.get('expected_return') if feature.get('expected_return') is not None else -999)
        >= float(policy.get('expected_min', 999))
    )


def v206_adaptive_forward_cycle():
    result = {'scanned': 0, 'matched': 0, 'created': 0, 'updated': 0, 'closed': 0}
    benchmark_result = v203_load_result()
    if not v203_result_is_valid(benchmark_result):
        result['error'] = 'current reproducible model is not ready'
        return result
    model = benchmark_result.get('model', {}) if isinstance(benchmark_result.get('model'), dict) else {}
    policy = benchmark_result.get('selected_policy', {}) if isinstance(benchmark_result.get('selected_policy'), dict) else {}
    if not model or not policy:
        result['error'] = 'adaptive model or policy is missing'
        return result
    btc = v191120_fetch_4h_candles('BTC', pages=1, bars_per_page=90)
    btc_features = v191120_btc_features(btc)
    features_by_asset = {}
    for asset in V191120_ENTRY_LAB_ASSETS:
        candles = v191120_fetch_4h_candles(asset, pages=1, bars_per_page=90)
        feature = v206_live_feature(asset, candles, btc_features)
        if not feature:
            continue
        feature.update(v204_predict(feature, model))
        features_by_asset[asset] = feature
        result['scanned'] += 1

    data = v202_forward_lab_load()
    open_rows = data.get('open', {}) if isinstance(data.get('open'), dict) else {}
    closed_rows = data.get('closed', []) if isinstance(data.get('closed'), list) else []
    now = time.time()
    active_assets = set()
    for key, trade in list(open_rows.items()):
        if not isinstance(trade, dict) or trade.get('cohort') != V206_FORWARD_COHORT:
            continue
        asset = str(trade.get('asset') or '').upper()
        active_assets.add(asset)
        feature = features_by_asset.get(asset, {})
        price = float(feature.get('price', 0) or 0)
        entry = float(trade.get('entry_price', 0) or 0)
        entry_time = float(trade.get('entry_time', 0) or 0)
        if price <= 0 or entry <= 0 or entry_time <= 0:
            continue
        age_h = max(0.0, (now - entry_time) / 3600.0)
        pct = round(v191120_pct(entry, price), 3)
        trade.update({'last_price': price, 'last_pct': pct, 'last_update_at': now})
        results = trade.setdefault('results', {})
        for name, hours in [('1h', 1), ('4h', 4), ('12h', 12), ('24h', 24), ('48h', 48)]:
            if age_h >= hours and name not in results:
                results[name] = pct
                result['updated'] += 1
        if age_h >= 48:
            trade.update({
                'status': 'closed',
                'closed_at': now,
                'final_pct': float(results.get('48h', pct) or pct),
            })
            closed_rows.append(trade)
            open_rows.pop(key, None)
            active_assets.discard(asset)
            result['closed'] += 1

    matches = [
        feature for feature in features_by_asset.values()
        if v206_policy_match(feature, policy)
    ]
    matches.sort(key=lambda row: float(row.get('evidence_score', -999) or -999), reverse=True)
    result['matched'] = len(matches)
    active_count = sum(
        1 for trade in open_rows.values()
        if isinstance(trade, dict) and trade.get('cohort') == V206_FORWARD_COHORT
    )
    if not bool(benchmark_result.get('qualified_for_forward_shadow')):
        result['active'] = active_count
        result['error'] = 'historical guard blocked new adaptive forward entries'
        data['open'] = open_rows
        data['closed'] = closed_rows[-400:]
        data['last_adaptive_cycle_at'] = now
        data['last_adaptive_cycle_result'] = dict(result)
        v202_forward_lab_save(data)
        return result

    for feature in matches:
        if active_count >= 4 or result['created'] >= 2:
            break
        asset = str(feature.get('asset') or '').upper()
        if asset in active_assets:
            continue
        key = f"{V206_FORWARD_COHORT}:{asset}:{int(feature.get('ts', 0) or 0)}"
        if key in open_rows or any(str(row.get('id') or '') == key for row in closed_rows if isinstance(row, dict)):
            continue
        price = float(feature.get('price', 0) or 0)
        if price <= 0:
            continue
        open_rows[key] = {
            'id': key,
            'cohort': V206_FORWARD_COHORT,
            'asset': asset,
            'entry_time': now,
            'entry_price': price,
            'last_price': price,
            'last_pct': 0.0,
            'status': 'open',
            'policy': dict(policy),
            'entry_features': dict(feature),
            'results': {},
            'created_by': V191111_VERSION,
            'note': 'Adaptive context forward PAPER only. Real BUY and autotrading remain OFF.',
        }
        active_assets.add(asset)
        active_count += 1
        result['created'] += 1

    result['active'] = active_count
    data['open'] = open_rows
    data['closed'] = closed_rows[-400:]
    data['last_adaptive_cycle_at'] = now
    data['last_adaptive_cycle_result'] = dict(result)
    v202_forward_lab_save(data)
    return result


def v206_maybe_forward_background(force=False):
    global V206_FORWARD_LAST_START
    now = time.time()
    if not force and now - float(V206_FORWARD_LAST_START or 0) < 3600:
        return False
    V206_FORWARD_LAST_START = now

    def worker():
        if not V206_FORWARD_LOCK.acquire(False):
            return
        shared_acquired = False
        try:
            shared_acquired = V202_FORWARD_LAB_LOCK.acquire(False)
            if not shared_acquired:
                return
            v206_adaptive_forward_cycle()
        except Exception as exc:
            print(f'v20.9 adaptive forward error: {exc}')
        finally:
            if shared_acquired:
                V202_FORWARD_LAB_LOCK.release()
            V206_FORWARD_LOCK.release()

    Thread(target=worker, daemon=True).start()
    return True


