def v19116_auto_quality_probe_scheduler(force=False, chat_id=None):
    """v20.9: legacy quality auto-probe cannot create new probes while benchmark guard blocks forward."""
    if not v209_forward_guard_ready():
        st = v19116_auto_probe_state() if 'v19116_auto_probe_state' in globals() else {}
        now = time.time()
        if isinstance(st, dict):
            st.update({
                'last_run': now,
                'version': V191111_VERSION,
                'last_created': 0,
                'last_new_assets': [],
                'last_blocked_reason': 'benchmark forward guard is BLOCK; auto quality probes are quarantined',
                'last_error': '',
            })
            try:
                v19116_save_auto_probe_state(st, sync=False)
            except Exception:
                pass
        return {
            'ran': True,
            'created': 0,
            'active': len(v19116_probe_assets_from_store()) if 'v19116_probe_assets_from_store' in globals() else 0,
            'new_assets': [],
            'sent': False,
            'blocked': True,
            'reason': 'benchmark_guard_block',
            'state': st,
        }
    if callable(_v209_old_auto_quality_probe_scheduler):
        return _v209_old_auto_quality_probe_scheduler(force=force, chat_id=chat_id)
    return {'ran': False, 'reason': 'scheduler unavailable'}


