def v1911101_section(title, body):
    return "\n\n" + "="*80 + "\n" + str(title) + "\n" + "="*80 + "\n" + str(body or "")


def v1911101_safe_call(fn_name, fallback=''):
    try:
        fn = globals().get(fn_name)
        if callable(fn):
            return str(fn())
    except Exception as e:
        return f"⚠️ {fn_name} error: {str(e)[:180]}"
    return fallback


